import React, { useCallback, useState, useRef, useMemo } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  IconButton,
  Backdrop
} from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWTooltip from '../../../FAWTooltip';
import FAWButton from '../../../FAWButton';
import { Search as SearchIcon, Settings as SettingsIcon, Edit as EditIcon, ArrowBack as ArrowBackIcon } from '@mui/icons-material';
import ExpandIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Expand.js";
import CollapseIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/Collapse.js";
import FAWDrawer from '../../../FAWDrawer';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import FAWConfirmDialogue from '../../../FAWConfirmDialogue';
import { ToastManager } from '../../../shared/ToastManager';
import SnippetForm from './SnippetForm';
import SnippetTaskManagementSection from './SnippetTaskManagementSection';
import SearchUDFModal from '../../../shared/SearchUDFModal';
import AdhocSettingsModal from '../../../shared/AdhocSettingsModal';
import TaskSettingsModal from '../../workflowdefinition/components/TaskSettingsModal';
import SnippetTaskDetail from './SnippetTaskDetail';
import NoResultsFound from '../../../shared/NoResultsFound';
import AddTaskDropdown from '../../workflowdefinition/components/AddTaskDropdown';
import { useSnippetWorkflowDefinitionState } from '../hooks/useSnippetWorkflowDefinitionState';
import '../../css/workflow.css';
import { useSnippetWorkflowDefinitionHandlers } from '../hooks/useSnippetWorkflowDefinitionHandlers';
import { isNewlyCreated, getWarningMessage } from '../../../shared/utils/formChangeDetection';

const SnippetWorkflowDefinitionManager = ({ snippetId, taskId, subcategoryOptionsByCategoryJson, allWorkflowDefs, onSuccess, onCancel }) => {
  const state = useSnippetWorkflowDefinitionState({ snippetId, subcategoryOptionsByCategoryJson, onSuccess, onCancel });
  
  // Ref for SnippetTaskDetail to access checkForChanges function
  const taskDetailRef = useRef(null);
  
  // State to track tree visibility for IF tasks
  // treeVisible = true means tree is hidden, task content is expanded (full width)
  // treeVisible = false means tree is visible, normal split view
  const [treeVisible, setTreeVisible] = useState(false);
  
  // Reset tree visibility when task changes (tree visible by default)
  React.useEffect(() => {
    setTreeVisible(false);
  }, [state.currentTask?.id]);
  
  const handleAddTask = (taskType) => {
    if (state.currentSnippetId) {
      // Check if task is newly created via ref FIRST
      const isNew = taskDetailRef?.current?.isNewlyCreated;
      
      // Check for changes using the SnippetTaskDetail component's checkForChanges function
      let hasChanges = false;
      if (taskDetailRef?.current?.checkForChanges) {
        hasChanges = taskDetailRef.current.checkForChanges();
      } else {
        // Fallback to parent state if ref is not available
        hasChanges = state.formChanged;
      }
      
      if (isNew || hasChanges) {
        // Get appropriate warning message using boolean flags
          const warningMessage = getWarningMessage(isNew, hasChanges);
        
        state.setConfirmationDialog({
          open: true,
          title: warningMessage?.title || 'Unsaved Changes',
          message: warningMessage?.message || 'You have unsaved changes. Are you sure you want to continue?',
          onConfirm: () => {
            state.setConfirmationDialog(prev => ({ ...prev, open: false }));
            createTask(taskType);
          },
          onCancel: () => {
            state.setConfirmationDialog(prev => ({ ...prev, open: false }));
          },
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: warningMessage?.severity || 'warning'
        });
        return;
      }
      
      createTask(taskType);
    }
  };
  
  const createTask = (taskType) => {
    const event = new CustomEvent('addTaskRequested', {
      detail: {
        snippetId: state.currentSnippetId,
        parentTaskId: 0,  // Plus icon always creates root-level tasks
        taskType: taskType
      }
    });
    window.dispatchEvent(event);
  };
  
  const handleCurrentTaskClear = React.useCallback(() => {
    state.setCurrentTask(null);
    state.setTaskDetail(null);
    state.setFormChanged(false);
    
    if (taskId) {
      const currentUrl = new URL(window.location.href);
      currentUrl.searchParams.delete('taskId');
      if (!currentUrl.searchParams.has('id') && snippetId) {
        currentUrl.searchParams.set('id', snippetId);
      }
      window.history.replaceState({}, '', currentUrl.toString());
    }
  }, [state.setCurrentTask, state.setTaskDetail, state.setFormChanged, taskId, snippetId]);

  const handlers = useSnippetWorkflowDefinitionHandlers({
    snippetId,
    currentSnippetId: state.currentSnippetId,
    setCurrentSnippetId: state.setCurrentSnippetId,
    taskId: taskId,
    onSuccess,
    onCancel,
    formRef: state.formRef,
    taskDetailRef: taskDetailRef,
    saving: state.saving,
    setSaving: state.setSaving,
    setValidating: state.setValidating,
    setDrawerOpen: state.setDrawerOpen,
    setError: state.setError,
    setSelectedWorkflows: state.setSelectedWorkflows,
    setCurrentTask: state.setCurrentTask,
    setTaskDetailLoading: state.setTaskDetailLoading,
    setTaskDetail: state.setTaskDetail,
    setTaskFetchError: state.setTaskFetchError,
    setFormChanged: state.setFormChanged,
    setSearchUDFModalOpen: state.setSearchUDFModalOpen,
    setAdhocSettingsModalOpen: state.setAdhocSettingsModalOpen,
    setPreconditionsModalOpen: state.setPreconditionsModalOpen,
    setInsertSnippetModalOpen: state.setInsertSnippetModalOpen,
    setSnippetTreeData: state.setSnippetTreeData,
    setConfirmationDialog: state.setConfirmationDialog,
    currentTask: state.currentTask,
    taskDetail: state.taskDetail,
    formChanged: state.formChanged,
    onCurrentTaskClear: handleCurrentTaskClear,
    fetchTreeData: state.fetchTreeData,
    setTreeDataError: state.setTreeDataError,
    setTreeLoading: state.setTreeLoading,
    setLoading: state.setLoading,
    setInitialData: state.setInitialData,
    setFullPageLoader: state.setFullPageLoader,
    setValidating: state.setValidating
  });

  React.useEffect(() => {
    try {
      if (taskId && state.snippetTreeData && state.snippetTreeData.length > 0) {
        const findTaskInTree = (nodes, targetId) => {
          for (const node of nodes) {
            if (node.id === targetId) {
              return node;
            }
            if (node.children && node.children.length > 0) {
              const found = findTaskInTree(node.children, targetId);
              if (found) return found;
            }
          }
          return null;
        };

        const targetTask = findTaskInTree(state.snippetTreeData, taskId);
        if (targetTask) {
          handlers.handleNodeSelect(targetTask);
        }
      }
    } catch (error) {
      console.error('Error in taskId useEffect:', error);
    }
  }, [taskId, state.snippetTreeData]);

  React.useEffect(() => {
    const handleTaskIdUpdate = (event) => {
      try {
        const { taskId: newTaskId, snippetId: eventSnippetId } = event.detail;
        
        if (eventSnippetId === snippetId) {
          const findTaskInTree = (nodes, targetId) => {
            for (const node of nodes) {
              if (node.id === targetId) {
                return node;
              }
              if (node.children && node.children.length > 0) {
                const found = findTaskInTree(node.children, targetId);
                if (found) return found;
              }
            }
            return null;
          };

          const targetTask = findTaskInTree(state.snippetTreeData, newTaskId);
          if (targetTask) {
            handlers.handleNodeSelect(targetTask);
          }
        }
      } catch (error) {
        console.error('Error handling taskIdUpdated event:', error);
      }
    };

    window.addEventListener('taskIdUpdated', handleTaskIdUpdate);

    return () => {
      window.removeEventListener('taskIdUpdated', handleTaskIdUpdate);
    };
  }, [snippetId, state.snippetTreeData]);

  const isNewSnippet = !snippetId || snippetId === 0;
  const showTreeView = !isNewSnippet && !state.drawerOpen;

  // Memoize drawer actions to prevent unnecessary re-renders and stale closures
  const drawerActions = useMemo(() => [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: handlers.handleCancel,
      disabled: state.saving,
      handlerType: 'custom'
    },
    {
      text: state.validating ? 'Validating...' : state.saving ? 'Saving...' : 'Save',
      variant: 'contained',
      color: 'primary',
      onClick: handlers.handleSaveClick,
      disabled: state.saving || state.validating,
      handlerType: 'custom',
      componentType: 'snippet'
    }
  ], [handlers.handleCancel, handlers.handleSaveClick, state.saving, state.validating]);

  return (
    <FAWErrorBoundary
      title="Snippet Error"
      message="An error occurred while loading the snippet. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('SnippetManager Error:', error, errorInfo);
      }}
      onReportError={(error) => {
      }}
    >
      <Box sx={{ 
        width: '100% !important', 
        maxWidth: '100% !important', 
        overflow: 'hidden !important',
        boxSizing: 'border-box !important'
      }}>
        <ToastManager />

        {showTreeView && (
          <Box sx={{ 
            backgroundColor: '#fbfbfb',
            minHeight: '100vh',
            width: '100% !important',
            maxWidth: '100% !important',
            overflow: 'hidden !important',
            boxSizing: 'border-box !important'
          }}>
            <Box sx={{ 
              display: 'flex', 
              justifyContent: 'space-between', 
              alignItems: 'center',
              p: '16px 0',
              backgroundColor: 'white',
              width: '100% !important',
              maxWidth: '100% !important',
              overflow: 'hidden !important',
              boxSizing: 'border-box !important'
            }}>
              <Box sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '12px',
                flex: 1
              }}>
                <FAWButton
                  variant="text"
                  size="medium"
                  iconOnly
                  onClick={() => {
                    if (onCancel) {
                      onCancel();
                    }
                  }}
                  sx={{ 
                    minWidth: 'auto',
                    width: '40px',
                    height: '40px',
                    borderRadius: '8px',
                    '&:hover': {
                      backgroundColor: '#f5f5f5'
                    }
                  }}
                >
                  <ArrowBackIcon sx={{ fontSize: '20px' }} />
                </FAWButton>
                
                <FAWTypography sx={{
                  fontWeight: 600,
                  fontSize: '30px',
                  lineHeight: '38px',
                  color: '#282e37',
                  letterSpacing: '0.2px'
                }}>
                  {state.initialData?.Name || (snippetId ? 'Edit Snippet' : 'Create Snippet')}
                </FAWTypography>
              </Box>

              <Box sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: '16px'
              }}>
                <FAWButton
                  className="snippet-definition-manager-edit-snippet-btn"
                  variant="contained"
                  size="medium"
                  startIcon={<EditIcon />}
                  onClick={() => state.setDrawerOpen(true)}
                  disabled={state.loading || (snippetId && !state.initialData)}
                  sx={{ 
                    background: 'var(--Gradient-primary-default, linear-gradient(180deg, var(--Color-Action-Primary-Default-gradient-start, #282E37) 0%, var(--Color-Action-Primary-Default-gradient-middle, #282E37) 50%, var(--Color-Action-Primary-Default-gradient-end, #282E37) 100%))',
                    color: 'white',
                    border: '1px solid #282e37',
                    borderRadius: 'var(--Radius-Lg, 12px)',
                    padding: '8px 16px',
                    fontSize: '16px',
                    fontWeight: 600,
                    textTransform: 'none',
                    minWidth: 'auto',
                    height: '40px',
                    '&:hover': {
                      background: 'var(--Gradient-primary-default, linear-gradient(180deg, var(--Color-Action-Primary-Default-gradient-start, #1a1d23) 0%, var(--Color-Action-Primary-Default-gradient-middle, #1a1d23) 50%, var(--Color-Action-Primary-Default-gradient-end, #1a1d23) 100%))',
                      borderColor: '#1a1d23'
                    },
                    '& .MuiButton-startIcon': {
                      marginRight: '8px',
                      '& svg': {
                        fontSize: '20px'
                      }
                    }
                  }}
                >
                  Edit Attributes
                </FAWButton>
              </Box>
            </Box>
            
            <Grid container spacing={3} sx={{ 
              width: '100%',
              maxWidth: '100% !important',
              minHeight: 600,
              boxSizing: 'border-box',
              margin: 0
            }}>
            <Grid item xs={12} md={state.currentTask?.Type === 'IF' && treeVisible ? 0 : 4} className="snippet-workflow-definition-manager-tree-panel" sx={{ 
              minWidth: 0,
              maxWidth: '100% !important',
              overflow: 'hidden !important',
              display: state.currentTask?.Type === 'IF' && treeVisible ? 'none' : 'block',
              boxSizing: 'border-box'
            }}>
              <Paper className="snippet-workflow-definition-manager-tree-paper" sx={{ 
                height: '100%', 
                display: 'flex', 
                flexDirection: 'column',
                backgroundColor: 'white',
                borderRadius: '12px',
                border: '1px solid #dadada',
                boxShadow: 'none',
                overflow: 'hidden !important',
                maxWidth: '100% !important',
                width: '100% !important',
                minWidth: 0,
                boxSizing: 'border-box'
              }}>
                <Box className="snippet-workflow-definition-manager-tree-header" sx={{ 
                  p: '8px 16px',
                  borderBottom: '1px solid #dadada',
                  borderTopLeftRadius: '12px',
                  borderTopRightRadius: '12px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  backgroundColor: 'white',
                  minHeight: '48px',
                  flexShrink: 0
                }}>
                  <FAWTypography className="snippet-workflow-definition-manager-tree-title" sx={{
                    fontWeight: 600,
                    fontSize: '18px',
                    lineHeight: '28px',
                    color: '#282e37',
                    letterSpacing: '0.2px'
                  }}>
                    Workflow Snippet
                  </FAWTypography>
                  <Box className="snippet-workflow-definition-manager-tree-actions" sx={{ display: 'flex', gap: '8px' }}>
                    <AddTaskDropdown 
                      onAddTask={handleAddTask}
                      disabled={!state.currentSnippetId || !state.snippetTreeData || state.snippetTreeData.length === 0}
                    />
                    
                    <FAWTooltip title="Search UDF">
                      <Box sx={{
                        display: 'none',
                        backgroundColor: (!snippetId || !state.snippetTreeData || state.snippetTreeData.length === 0) ? '#ccc' : '#282e37',
                        borderRadius: '8px',
                        p: '4px',
                        alignItems: 'center',
                        justifyContent: 'center',
                        width: '32px',
                        height: '32px',
                        cursor: (!snippetId || !state.snippetTreeData || state.snippetTreeData.length === 0) ? 'not-allowed' : 'pointer',
                        opacity: (!snippetId || !state.snippetTreeData || state.snippetTreeData.length === 0) ? 0.5 : 1,
                        '&:hover': {
                          backgroundColor: (!snippetId || !state.snippetTreeData || state.snippetTreeData.length === 0) ? '#ccc' : '#1a1d23'
                        }
                      }}
                      onClick={() => {
                        if (snippetId && state.snippetTreeData && state.snippetTreeData.length > 0) {
                          state.setDrawerOpen(true);
                        }
                      }}>
                        <SearchIcon sx={{ color: 'white', fontSize: '24px' }} />
                      </Box>
                    </FAWTooltip>
                  </Box>
                </Box>

                <Box className="snippet-workflow-definition-manager-tree-content" sx={{ 
                  flex: 1, 
                  overflow: 'auto !important', 
                  overflowX: 'hidden !important',
                  overflowY: 'auto !important',
                  p: '8px 16px 16px 8px',
                  backgroundColor: 'white',
                  borderBottomLeftRadius: '12px',
                  borderBottomRightRadius: '12px',
                  minWidth: 0,
                  width: '100% !important',
                  maxWidth: '100% !important',
                  boxSizing: 'border-box',
                  '& .atlas_nodeContent .rst__rowContents .rst__rowTitle': {
                    overflow: 'visible !important',
                    textOverflow: 'clip !important',
                    maxWidth: 'none !important',
                    width: 'auto !important',
                    minWidth: '200px !important'
                  }
                }}>
                  <SnippetTaskManagementSection
                    snippetId={state.currentSnippetId || snippetId}
                    snippetTreeData={state.snippetTreeData}
                    currentTask={state.currentTask}
                    taskDetailLoading={state.taskDetailLoading}
                    taskDetail={state.taskDetail}
                    setTaskDetail={state.setTaskDetail}
                    formChanged={state.formChanged}
                    setFormChanged={state.setFormChanged}
                    searchUDFModalOpen={state.searchUDFModalOpen}
                    adhocSettingsModalOpen={state.adhocSettingsModalOpen}
                    preconditionsModalOpen={state.preconditionsModalOpen}
                    insertSnippetModalOpen={state.insertSnippetModalOpen}
                    onNodeSelect={handlers.handleNodeSelect}
                    onTreeAction={handlers.handleTreeAction}
                    onTreeError={handlers.handleTreeError}
                    onSearchUDFOpen={handlers.handleSearchUDFOpen}
                    onSearchUDFClose={handlers.handleSearchUDFClose}
                    onAdhocSettingsOpen={handlers.handleAdhocSettingsOpen}
                    onAdhocSettingsClose={handlers.handleAdhocSettingsClose}
                    onPreconditionsOpen={handlers.handlePreconditionsOpen}
                    onPreconditionsClose={handlers.handlePreconditionsClose}
                    onInsertSnippetOpen={handlers.handleInsertSnippetOpen}
                    onInsertSnippetClose={handlers.handleInsertSnippetClose}
                    onTreeDataRefresh={handlers.handleTreeDataRefresh}
                    onSuccess={handlers.handleSuccess}
                    setConfirmationDialog={state.setConfirmationDialog}
                    showTreeOnly={true}
                    fullPageLoader={state.fullPageLoader}
                    setFullPageLoader={state.setFullPageLoader}
                    error={state.error}
                    treeDataError={state.treeDataError}
                    retryTreeData={state.retryTreeData}
                    treeLoading={state.treeLoading}
                    setTreeLoading={state.setTreeLoading}
                  />
                </Box>
              </Paper>
            </Grid>

            <Grid item xs={12} md={state.currentTask?.Type === 'IF' && treeVisible ? 12 : 8} sx={{ 
              minWidth: 0,
              minHeight: 0,
              maxWidth: '100% !important',
              display: 'flex',
              flexDirection: 'column',
              boxSizing: 'border-box'
            }}>
              <Paper className="snippet-workflow-definition-manager-content-paper" sx={{ 
                height: '100%', 
                display: 'flex', 
                flexDirection: 'column',
                backgroundColor: 'white',
                borderRadius: '12px',
                border: '1px solid #dadada',
                boxShadow: 'none',
                overflow: 'hidden !important',
                maxWidth: '100% !important',
                width: '100% !important',
                minWidth: 0,
                boxSizing: 'border-box'
              }}>
                <Box className="snippet-workflow-definition-manager-content-header" sx={{ 
                  p: '16px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  backgroundColor: 'white',
                  borderTopLeftRadius: '12px',
                  borderTopRightRadius: '12px'
                }}>
                  {state.currentTask ? (
                    <FAWTypography className="snippet-workflow-definition-manager-content-title" sx={{
                      overflow: 'hidden',
                      color: 'var(--Color-Type-Default, #282E37)',
                      fontFeatureSettings: "'liga' off, 'clig' off",
                      textOverflow: 'ellipsis',
                      fontSize: '18px',
                      fontStyle: 'normal',
                      fontWeight: 600,
                      lineHeight: '28px',
                      letterSpacing: '0.2px'
                    }}>
                      {state.taskDetail?.Name || state.taskDetail?.name || state.currentTask.Name || state.currentTask.name || 'Untitled Task'}
                    </FAWTypography>
                  ) : (
                   null
                  )}
                  {state.currentTask && state.taskDetail && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                      {state.currentTask?.Type === 'IF' && (
                        <IconButton 
                          className="snippet-workflow-definition-manager-tree-toggle-button"
                          size="small" 
                          onClick={() => setTreeVisible(!treeVisible)}
                          sx={{ color: '#666666' }}
                          title={treeVisible ? 'Show Tree (Collapse Task)' : 'Hide Tree (Expand Task)'}
                        >
                          {treeVisible ? <CollapseIcon /> : <ExpandIcon />}
                        </IconButton>
                      )}
                      <IconButton 
                        className="snippet-workflow-definition-manager-task-settings-button"
                        size="small" 
                        onClick={() => state.setSettingsModalOpen(true)}
                        sx={{ color: '#666666' }}
                      >
                        <SettingsIcon />
                      </IconButton>
                    </Box>
                  )}
                </Box>

                <Box className="snippet-workflow-definition-manager-content-area" sx={{ 
                  flex: 1, 
                  overflow: 'auto', 
                  p: 2,
                  minWidth: 0,
                  maxWidth: '100% !important',
                  width: '100% !important',
                  boxSizing: 'border-box !important',
                  '& > *': {
                    maxWidth: '100% !important',
                    width: '100% !important',
                    boxSizing: 'border-box !important'
                  }
                }}>
                  <Box className="snippet-workflow-definition-manager-task-management-section" sx={{
                    maxWidth: '100% !important',
                    width: '100% !important',
                    overflow: 'hidden !important',
                    boxSizing: 'border-box !important'
                  }}>
                    {state.currentTask ? (
                      <Box sx={{
                        maxWidth: '100% !important',
                        width: '100% !important',
                        overflow: 'hidden !important',
                        boxSizing: 'border-box !important'
                      }}>
                        <SnippetTaskDetail
                        ref={taskDetailRef}
                        taskDetail={state.taskDetail}
                        loading={state.taskDetailLoading}
                        onSave={(taskData) => handlers.handleTaskSave(taskData, state.currentTask)}
                        onCancel={() => handlers.handleTaskCancel(state.currentTask)}
                        onFormChange={(changed) => {
                          if (state.setFormChanged) {
                            state.setFormChanged(changed);
                          }
                        }}
                        readOnly={false}
                        snippetId={snippetId}
                        taskId={state.currentTask.id}
                      />
                      </Box>
                    ) : (
                      <NoResultsFound
                        title="No Task Selected"
                        subtitle="Click a task in the tree to view and manage its details"
                        className="snippet-workflow-definition-manager-no-task-selected"
                      />
                    )}
                  </Box>
                </Box>
              </Paper>
            </Grid>
          </Grid>
          </Box>
        )}

        <FAWDrawer
          className="snippet-manager-drawer"
          open={state.drawerOpen}
          onClose={handlers.handleCloseDrawer}
          title={snippetId ? 'Edit Snippet' : 'Add new snippet'}
          width={800}
          anchor="right"
          variant="temporary"
          showCloseButton={true}
          showHeader={true}
          customFooter={true}
          actions={drawerActions}
        >
          {state.loading ? (
            <Box className="snippet-manager-drawer-loading" sx={{ p: 3 }}>
              <FAWSkeleton variant="form" />
            </Box>
          ) : (
            <SnippetForm
              ref={state.formRef}
              snippetId={snippetId}
              onSave={handlers.handleSaveClick}
              onCancel={handlers.handleCancel}
              initialData={state.initialData}
              options={state.options}
              subcategoryOptionsByCategoryJson={subcategoryOptionsByCategoryJson}
              allWorkflowDefs={allWorkflowDefs}
            />
          )}
        </FAWDrawer>

        <TaskSettingsModal
          open={state.settingsModalOpen}
          onClose={() => state.setSettingsModalOpen(false)}
          workflowId={snippetId}
          taskId={state.currentTask?.id}
          onSave={handlers.handleTaskSettingsSave}
          saving={state.saving}
          readOnly={false}
          isSectionTask={state.currentTask?.Type === 'SECTION'}
          isSnippet={true}
        />

        <SearchUDFModal
          open={state.searchUDFModalOpen}
          onClose={handlers.handleSearchUDFClose}
          entityId={state.currentSnippetId}
          entityType="snippet"
        />

        <AdhocSettingsModal
          open={state.adhocSettingsModalOpen}
          onClose={handlers.handleAdhocSettingsClose}
          entityId={state.currentSnippetId}
          entityType="snippet"
          initialData={state.initialData}
          onSave={handlers.handleAdhocSettingsSave}
        />

        <FAWConfirmDialogue
          open={state.confirmationDialog.open}
          title={state.confirmationDialog.title}
          message={state.confirmationDialog.message}
          onConfirm={state.confirmationDialog.onConfirm}
          onClose={state.confirmationDialog.onCancel}
          confirmLabel={state.confirmationDialog.confirmText}
          cancelLabel={state.confirmationDialog.cancelText}
          variant={state.confirmationDialog.severity === 'error' ? 'delete' : 'info'}
        />

        <Backdrop
          open={state.fullPageLoader.open}
          sx={{
            color: '#fff',
            zIndex: (theme) => theme.zIndex.drawer + 1,
            backgroundColor: 'rgba(0, 0, 0, 0.5)'
          }}
        >
          <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
            <FAWLoader size={40} />
            <FAWTypography variant="h6" sx={{ color: 'white' }}>
              {state.fullPageLoader.message}
            </FAWTypography>
          </Box>
        </Backdrop>
      </Box>
    </FAWErrorBoundary>
  );
};

