import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Box,
  Alert
} from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWButton from '../../../FAWButton';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import { snippetApi } from '../services/snippetApi';

/**
 * Preconditions Modal Component for Snippets
 * Based on PreconditionsModal from workflow definition
 */
const PreconditionsModal = ({
  open,
  onClose,
  snippetId,
  taskId,
  onSave
}) => {
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);
  const [preconditionData, setPreconditionData] = useState(null);
  const [formData, setFormData] = useState({});

  // Load preconditions when modal opens
  useEffect(() => {
    if (open && snippetId && taskId) {
      loadPreconditions();
    }
  }, [open, snippetId, taskId]);

  const loadPreconditions = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await snippetApi.getPreconditionForm(snippetId, taskId);
      if (response.success) {
        setPreconditionData(response.data);
        // Initialize form data if needed
        setFormData(response.data || {});
      } else {
        setError(response.message || 'Failed to load preconditions');
      }
    } catch (err) {
      console.error('Error loading preconditions:', err);
      setError(err.message || 'Failed to load preconditions');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    setError(null);

    try {
      const response = await snippetApi.savePreconditions(snippetId, taskId, formData);
      if (response.success) {
        if (onSave) {
          onSave(response.data);
        }
        onClose();
      } else {
        setError(response.message || 'Failed to save preconditions');
      }
    } catch (err) {
      console.error('Error saving preconditions:', err);
      setError(err.message || 'Failed to save preconditions');
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    setFormData({});
    setError(null);
    onClose();
  };

  return (
    <FAWErrorBoundary
      title="Preconditions Modal Error"
      message="An error occurred while loading the preconditions modal. Please try again."
      showDetails={false}
      onError={(error, errorInfo) => {
        console.error('PreconditionsModal Error:', error, errorInfo);
      }}
    >
      <Dialog
        className="snippet-preconditions-modal"
        open={open}
        onClose={handleCancel}
        maxWidth="md"
        fullWidth
        PaperProps={{
          sx: { minHeight: '500px' }
        }}
      >
        <DialogTitle className="snippet-preconditions-modal-title">
          Define Preconditions
        </DialogTitle>

        <DialogContent className="snippet-preconditions-modal-content">
          {loading ? (
            <Box className="snippet-preconditions-modal-loading" sx={{ 
              display: 'flex', 
              justifyContent: 'center', 
              alignItems: 'center', 
              minHeight: 200 
            }}>
              <FAWSkeleton variant="rectangular" width={40} height={40} />
            </Box>
          ) : error ? (
            <Alert className="snippet-preconditions-modal-error" severity="error" sx={{ mb: 2 }}>
              {error}
            </Alert>
          ) : preconditionData ? (
            <Box className="snippet-preconditions-modal-form">
              {/* Render the precondition form content */}
              <FAWTypography variant="body1" sx={{ mb: 2 }}>
                Configure the preconditions for this task. Preconditions determine when this task can be executed.
              </FAWTypography>
              
              {/* Render structured JSON data from API */}
              <Box 
                className="snippet-preconditions-modal-content"
                sx={{ 
                  p: 2, 
                  border: '1px solid #e0e0e0', 
                  borderRadius: 1,
                  backgroundColor: '#ffffff'
                }}
              >
                <FAWTypography variant="h6" sx={{ mb: 2 }}>
                  Precondition Configuration
                </FAWTypography>
                
                {/* Display precondition data structure */}
                <Box sx={{ mb: 2 }}>
                  <FAWTypography variant="body2" color="text.secondary">
                    Task: {preconditionData.CurrentWorkflowDef?.Name || 'Unknown'}
                  </FAWTypography>
                  <FAWTypography variant="body2" color="text.secondary">
                    Available Tasks: {preconditionData.CurrentWorkflowDef?.WorkflowTaskDefs?.length || 0}
                  </FAWTypography>
                </Box>

                {/* This would be replaced with actual precondition form components */}
                <Box sx={{ 
                  p: 2, 
                  border: '1px solid #e0e0e0', 
                  borderRadius: 1,
                  backgroundColor: '#f9f9f9'
                }}>
                  <FAWTypography variant="body2" color="text.secondary">
                    Precondition form components would be rendered here based on the structured data.
                    Available tasks: {preconditionData.CurrentWorkflowDef?.WorkflowTaskDefs?.map(task => task.Name).join(', ') || 'None'}
                  </FAWTypography>
                </Box>
              </Box>
            </Box>
          ) : (
            <Box className="snippet-preconditions-modal-empty" sx={{ 
              display: 'flex', 
              justifyContent: 'center', 
              alignItems: 'center', 
              minHeight: 200 
            }}>
              <FAWTypography variant="body1" color="text.secondary">
                No preconditions available for this task.
              </FAWTypography>
            </Box>
          )}
        </DialogContent>

        <DialogActions className="snippet-preconditions-modal-actions" sx={{ p: 2 }}>
          <FAWButton
            className="snippet-preconditions-modal-cancel-button"
            onClick={handleCancel}
            disabled={saving}
            variant="outlined"
          >
            Cancel
          </FAWButton>
          <FAWButton
            className="snippet-preconditions-modal-save-button"
            onClick={handleSave}
            disabled={saving || loading}
            variant="contained"
            color="primary"
          >
            {saving ? 'Saving...' : 'Save'}
          </FAWButton>
        </DialogActions>
      </Dialog>
    </FAWErrorBoundary>
  );
};

export default PreconditionsModal;
