import { useState, useEffect, useCallback, useRef } from 'react';
import { snippetApi } from '../services/snippetApi';
import { showToast } from '../../../shared/ToastManager';

/**
 * Custom hook for managing SnippetManager state
 * Extracts all state management logic to make the component more modular
 */
export const useSnippetWorkflowDefinitionState = ({ snippetId, subcategoryOptionsByCategoryJson, onSuccess, onCancel }) => {
  // Core state - Initialize drawer based on whether this is a new snippet
  const [drawerOpen, setDrawerOpen] = useState(!snippetId || snippetId === 0);
  const [saving, setSaving] = useState(false);
  const [validating, setValidating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState(0);
  
  // Form and data state
  const formRef = useRef(null);
  const [options, setOptions] = useState({
    categories: [],
    subcategories: []
  });
  const [initialData, setInitialData] = useState(null);
  const [selectedWorkflows, setSelectedWorkflows] = useState([]);
  
  // Tree-related state (similar to workflow definition)
  const [currentTask, setCurrentTask] = useState(null);
  const [taskDetailLoading, setTaskDetailLoading] = useState(false);
  const [taskDetail, setTaskDetail] = useState(null);
  const [taskFetchError, setTaskFetchError] = useState(null);
  const [formChanged, setFormChanged] = useState(false);
  const [snippetTreeData, setSnippetTreeData] = useState(null);
  const [treeDataError, setTreeDataError] = useState(null);
  const [treeLoading, setTreeLoading] = useState(false);
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Yes',
    cancelText: 'No',
    severity: 'warning'
  });

  // Full page loader state
  const [fullPageLoader, setFullPageLoader] = useState({
    open: false,
    message: 'Loading...'
  });

  // Modal states
  const [searchUDFModalOpen, setSearchUDFModalOpen] = useState(false);
  const [adhocSettingsModalOpen, setAdhocSettingsModalOpen] = useState(false);
  const [preconditionsModalOpen, setPreconditionsModalOpen] = useState(false);
  const [insertSnippetModalOpen, setInsertSnippetModalOpen] = useState(false);
  const [settingsModalOpen, setSettingsModalOpen] = useState(false);

  // Additional state for dynamic snippetId management
  const [currentSnippetId, setCurrentSnippetId] = useState(snippetId);

  // Auto-open drawer when component mounts (only for new snippets)
  useEffect(() => {
    // Only auto-open drawer for new snippets (snippetId is 0 or null)
    const isNewSnippet = !snippetId || snippetId === 0;
    setDrawerOpen(isNewSnippet);
  }, [snippetId]);

  // Update currentSnippetId when snippetId prop changes
  useEffect(() => {
    setCurrentSnippetId(snippetId);
  }, [snippetId]);

  // Load data function
  const loadData = useCallback(async () => {
    setLoading(true);
    setError(null);
    
    try {
      // Load options
      const optionsData = await snippetApi.getOptions();
      setOptions(optionsData);

      // Load snippet data if editing
      if (snippetId) {
        const snippetData = await snippetApi.getSnippet(snippetId);
        
        // Use server-side subcategory options if available
        if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
          snippetData.subcategoryOptionsByCategoryJson = subcategoryOptionsByCategoryJson;
        }
        
        setInitialData(snippetData);
        
        // If category is already selected, fetch subcategories for it
        if (snippetData.CategoryCode) {
          try {
            const subcategories = await snippetApi.getSubcategories(snippetData.CategoryCode);
            if (subcategories && subcategories.length > 0) {
              // Update the subcategory options in the loaded data
              const updatedData = { ...snippetData };
              if (!updatedData.subcategoryOptionsByCategoryJson) {
                updatedData.subcategoryOptionsByCategoryJson = {};
              }
              updatedData.subcategoryOptionsByCategoryJson[snippetData.CategoryCode] = subcategories;
              setInitialData(updatedData);
            }
          } catch (error) {
            console.warn('Could not load subcategories for existing category:', error);
          }
        }
        
        // Load snippet tree data for existing snippets
        await fetchTreeData(); // Use unified function, no toast for initial load
      } else {
        // For new snippets, use server-side subcategory options if available
        if (subcategoryOptionsByCategoryJson && Object.keys(subcategoryOptionsByCategoryJson).length > 0) {
          setInitialData({ subcategoryOptionsByCategoryJson });
        }
      }
    } catch (err) {
      console.error('Error loading data:', err);
      showToast.error(err.message || 'Failed to load data');
      
      // Set treeDataError when the main API call fails
      // This ensures the retry button appears for snippet tree data errors
      if (snippetId) {
        setTreeDataError(err.message || 'Failed to load data');
        setSnippetTreeData([]);
      }
    } finally {
      setLoading(false);
    }
  }, [snippetId, subcategoryOptionsByCategoryJson]);

  // Unified function to fetch snippet tree data with proper error handling
  const fetchTreeData = useCallback(async (externalSetTreeLoading = null, explicitSnippetId = null) => {
    // Use explicit ID if provided (for async state updates), otherwise use currentSnippetId from state
    const snippetIdToUse = explicitSnippetId || currentSnippetId;
    
    if (!snippetIdToUse) {
      return [];
    }
    
    // Clear error, show loader
    setTreeDataError(null);
    // If external loader provided, use it; otherwise manage internal treeLoading (matches workflow definition pattern)
    if (externalSetTreeLoading) {
      externalSetTreeLoading(true);
    } else {
      setTreeLoading(true);
    }
    
    try {
      const treeData = await snippetApi.getSnippetTree(snippetIdToUse);
      setSnippetTreeData(treeData || []);
      // Success: clear loader, clear error
      if (externalSetTreeLoading) {
        externalSetTreeLoading(false);
      } else {
        setTreeLoading(false);
      }
      setTreeDataError(null);
      return treeData || [];
    } catch (error) {
      console.error('Error fetching snippet tree data:', error);
      // Fail: set error, hide loader
      const errorMessage = error.message || 'Failed to load snippet tree data';
      setTreeDataError(errorMessage);
      if (externalSetTreeLoading) {
        externalSetTreeLoading(false);
      } else {
        setTreeLoading(false);
      }
      // Show toast for retry attempts
      showToast.error(errorMessage, 5000);
      return [];
    }
  }, [currentSnippetId, setSnippetTreeData, setTreeDataError, setTreeLoading]);

  // Load data when component mounts
  useEffect(() => {
    loadData();
  }, [loadData]);

  // Retry function for tree data - uses the unified fetchTreeData function
  const retryTreeData = useCallback(async (setTreeLoading = null) => {
    try {
      const result = await fetchTreeData(setTreeLoading);
      if (result) {
        showToast.success('Snippet tree data loaded successfully', 3000);
      }
      return result;
    } catch (error) {
      console.error('Retry failed:', error);
      // Ensure loading state is cleared even if fetchTreeData fails
      if (setTreeLoading) setTreeLoading(false);
      throw error;
    }
  }, [fetchTreeData]);


  // Beforeunload warning for newly created tasks (matches legacy behavior)
  useEffect(() => {
    const handleBeforeUnload = (e) => {
      if (taskDetail && taskDetail.NewlyCreated) {
        e.preventDefault();
        e.returnValue = "The new task definition has not yet been saved. Do you want to continue without saving?";
        return e.returnValue;
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [taskDetail]);

  return {
    // State
    drawerOpen,
    setDrawerOpen,
    saving,
    setSaving,
    validating,
    setValidating,
    loading,
    setLoading,
    error,
    setError,
    activeTab,
    setActiveTab,
    options,
    setOptions,
    initialData,
    setInitialData,
    selectedWorkflows,
    setSelectedWorkflows,
    formRef,
    
    // Tree-related state
    currentTask,
    setCurrentTask,
    taskDetailLoading,
    setTaskDetailLoading,
    taskDetail,
    setTaskDetail,
    taskFetchError,
    setTaskFetchError,
    formChanged,
    setFormChanged,
    snippetTreeData,
    setSnippetTreeData,
    treeDataError,
    setTreeDataError,
    retryTreeData,
    confirmationDialog,
    setConfirmationDialog,
    fullPageLoader,
    setFullPageLoader,
    searchUDFModalOpen,
    setSearchUDFModalOpen,
    adhocSettingsModalOpen,
    setAdhocSettingsModalOpen,
    preconditionsModalOpen,
    setPreconditionsModalOpen,
    insertSnippetModalOpen,
    setInsertSnippetModalOpen,
    settingsModalOpen,
    setSettingsModalOpen,
    
    // Additional state for dynamic snippetId management
    currentSnippetId,
    setCurrentSnippetId,
    
    // Tree loading state
    treeLoading,
    setTreeLoading,
    
    // Functions
    loadData,
    fetchTreeData,
    retryTreeData
  };
};
