import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { Box, TextField, InputAdornment, IconButton } from '@mui/material';
import { Search as SearchIcon, Close as CloseIcon } from '@mui/icons-material';
import { useGridApiRef } from '@mui/x-data-grid-pro';
import FAWTypography from '../../../FAWTypography';
import FAWTooltip from '../../../FAWTooltip';
// Keep FAWAgGrid for verification - will remove after UI testing
// import FAWAgGrid from '../../../FAWAgGrid';
import FAWTable from '../../../FAWTable/FAWTable';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import FAWDrawer from '../../../FAWDrawer';
import FAWButtonGroupTabs from '../../../FAWButtonGroupTabs';
import { snippetApi } from '../services/snippetApi';
import { colors } from '../../../../../utils/designTokens';

const WorkflowAssociationTable = ({ 
  snippetId, 
  snippetName = '',
  allWorkflowDefs = [], 
  selectedWorkflows: propSelectedWorkflows = [], 
  onAssociationsChange,
  onClose
}) => {
  const [workflowAssociations, setWorkflowAssociations] = useState(allWorkflowDefs);
  const [selectedWorkflows, setSelectedWorkflows] = useState(propSelectedWorkflows);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeTab, setActiveTab] = useState(0); // 0 = All Workflows, 1 = Added
  // FAWTable apiRef
  const apiRef = useGridApiRef();
  // Keep old gridApiRef for commented FAWAgGrid code
  const gridApiRef = useRef(null);

  // Load workflow associations when component mounts
  useEffect(() => {
    loadWorkflowAssociations();
  }, [snippetId]);

  // Cleanup grid API ref on unmount
  useEffect(() => {
    return () => {
      gridApiRef.current = null;
    };
  }, []);

  // Handle selection changes from FAWTable
  const handleSelectionModelChange = useCallback((newSelection) => {
    // Deep compare to prevent unnecessary updates
    const sortedNew = [...newSelection].sort();
    const sortedCurrent = [...selectedWorkflows].sort();
    
    if (sortedNew.length === sortedCurrent.length && 
        sortedNew.every((value, index) => value === sortedCurrent[index])) {
      return;
    }
    
    setSelectedWorkflows(newSelection);
  }, [selectedWorkflows]);

  // Copy from parent only on initial load
  useEffect(() => {
    setSelectedWorkflows(propSelectedWorkflows);
  }, []); // Only run once on mount

  // Helper function to update grid selection (for old FAWAgGrid - kept for reference)
  const updateGridSelection = useCallback(() => {
    if (!gridApiRef.current) return;
    
    try {
      // Clear current selection first
      gridApiRef.current.deselectAll();
      
      // Select nodes that should be selected
      gridApiRef.current.forEachNode(node => {
        if (node.data && selectedWorkflows.includes(node.data.id)) {
          node.setSelected(true);
        }
      });
      
    } catch (error) {
      console.error('WorkflowAssociationTable: Error updating grid selection:', error);
      setError(`Failed to update selection: ${error.message}`);
    }
  }, [selectedWorkflows]);

  // Update grid selection when selectedWorkflows changes (removed circular dependency) - OLD AG Grid code
  // useEffect(() => {
  //   if (gridApiRef.current && workflowAssociations.length > 0) {
  //     updateGridSelection();
  //   }
  // }, [selectedWorkflows, workflowAssociations]); // Removed updateGridSelection from dependencies

  const loadWorkflowAssociations = async () => {
    setLoading(true);
    setError(null);

    try {

      // Use the AllWorkflowDefs data from props (like legacy did)
      if (allWorkflowDefs && allWorkflowDefs.length > 0) {
        // Ensure each workflow has required fields and consistent ID
        const associationsWithId = allWorkflowDefs.map(workflow => ({
          ...workflow,
          id: workflow.Id || workflow.id || workflow.SNo, // Standardize on 'id' - handle both Id and id
        }));
        setWorkflowAssociations(associationsWithId);
      } else {
        // Fallback to API call if no data provided
        const associations = await snippetApi.getWorkflowAssociations(snippetId || 0);
        
        // Ensure consistent ID field and mark workflows as added
        const processedAssociations = associations.map(workflow => ({
          ...workflow,
          id: workflow.Id || workflow.id || workflow.SNo, // Standardize on 'id' - handle both Id and id
          added: propSelectedWorkflows.includes(workflow.Id || workflow.id || workflow.SNo),
        }));
        
        setWorkflowAssociations(processedAssociations);
      }
    } catch (err) {
      console.error('Error loading workflow associations:', err);
      setError(err.message || 'Failed to load workflow associations');
    } finally {
      setLoading(false);
    }
  };



  // Handle selection changes from the grid (OLD AG Grid code - kept for reference)
  const handleSelectionChanged = useCallback((params) => {
    const selectedNodes = params.api.getSelectedNodes();
    const selectedIds = selectedNodes.map(node => node.data.id);
    
    setSelectedWorkflows(selectedIds);
    
    // Don't call onAssociationsChange here - wait for Save button
    // This prevents data from being added to parent until Save is clicked
  }, []);

  // Handle grid ready (OLD AG Grid code - kept for reference)
  const handleGridReady = useCallback((params) => {
    gridApiRef.current = params.api;
  }, []);

  // Handle first data rendered (OLD AG Grid code - kept for reference)
  const handleFirstDataRendered = useCallback(() => {
    // Set initial selection after data is fully rendered
    if (selectedWorkflows.length > 0) {
      updateGridSelection();
    }
  }, [selectedWorkflows, updateGridSelection]);

  // Filter workflows based on search term and active tab
  const filteredWorkflows = useMemo(() => {
    let filtered = workflowAssociations;

    // Filter by search term
    if (searchTerm) {
      filtered = filtered.filter(workflow => 
        workflow.Name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        workflow.Description?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        workflow.CategoryMeaning?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        workflow.SubcategoryMeaning?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    // Filter by tab
    if (activeTab === 1) { // Added tab
      filtered = filtered.filter(workflow => selectedWorkflows.includes(workflow.id));
    }

    return filtered;
  }, [workflowAssociations, searchTerm, activeTab, selectedWorkflows]);

  // Handle tab change
  const handleTabChange = (newValue) => {
    setActiveTab(newValue);
  };

  // Handle search change
  const handleSearchChange = (event) => {
    setSearchTerm(event.target.value);
  };

  // Handle drawer close
  const handleDrawerClose = () => {
    if (onClose) {
      onClose();
    }
  };

  // Column definitions for FAWTable
  const columns = useMemo(() => [
    {
      field: 'Name',
      headerName: 'Name',
      flex: 1,
      minWidth: 200,
      sortable: true,
      filterable: true,
    }
  ], []);

  // Convert filteredWorkflows to rows format for FAWTable
  const rows = useMemo(() => {
    return filteredWorkflows.map(workflow => ({
      id: workflow.id,
      Name: workflow.Name || workflow.name || '',
    }));
  }, [filteredWorkflows]);

  // Column definitions with proper checkbox setup - Only Name column as per image (OLD AG Grid code - kept for reference)
  const columnDefs = [
    {
      field: 'Name',
      headerName: 'Name',
      flex: 1, // Take full width
      filter: 'agTextColumnFilter',
      sortable: true,
      checkboxSelection: true, // Enable checkbox for first column
      headerCheckboxSelection: true, // Enable header checkbox for select all
      headerCheckboxSelectionFilteredOnly: true, // Only select filtered rows
    }
  ];

  // Loading state
  if (loading) {
    return (
      <Box className="workflow-association-table-loading" display="flex" justifyContent="center" p={3}>
        <FAWTypography>Loading workflow associations...</FAWTypography>
      </Box>
    );
  }

  // Error state
  if (error) {
    return (
      <Box className="workflow-association-table-error" p={2}>
        <FAWTypography color="error">{error}</FAWTypography>
      </Box>
    );
  }

  // Drawer mode content
  const drawerContent = (
    <FAWErrorBoundary
      title="Table Error"
      message="An error occurred while rendering the workflow association table."
      showDetails={false}
      onError={(error, errorInfo) => {
        console.error('WorkflowAssociationTable Error:', error, errorInfo);
      }}
    >
      <Box 
        className="workflow-association-drawer-container" 
        sx={{ 
          height: '100%', 
          display: 'flex', 
          flexDirection: 'column',
           // Prevent drawer body from scrolling
        }}
      >
        {/* Search Bar */}
        <Box sx={{ p: 2, flexShrink: 0 }}>
          <TextField
            fullWidth
            placeholder="Search by name"
            value={searchTerm}
            onChange={handleSearchChange}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <SearchIcon />
                </InputAdornment>
              ),
            }}
            size="small"
            sx={{
              '& .MuiOutlinedInput-root': {
                backgroundColor: '#ffffff'
              }
            }}
          />
        </Box>

        {/* Button Group Tabs */}
        <Box sx={{ px: 2, pb: 2, flexShrink: 0  }}>
          <FAWButtonGroupTabs
            options={[
              { value: 0, label: 'All Workflows' },
              { value: 1, label: 'Added' }
            ]}
            selected={activeTab}
            onChange={handleTabChange}
            size="medium"
            sx={{ 
              borderRadius: '8px',
              justifyContent: 'flex-start',
              fontSize: '16px',
            }}
          />
        </Box>

        {/* FAWTable - Scrollable container */}
        <Box 
          className="workflow-association-table-grid-container" 
          sx={{ 
            flex: 1, 
            px: 2,
            pb: 2,
            display: 'flex',
            flexDirection: 'column',
            minHeight: 0, // Important for flex child to allow scrolling
            
          }}
        >
          <FAWTable
            apiRef={apiRef}
            rows={rows}
            columns={columns}
            enableMultiSelect={true}
            hasDisableRowSelectionClick={true}
            onRowSelectionModelChange={handleSelectionModelChange}
            rowSelectionModel={selectedWorkflows}
            getRowId={(row) => row.id}
            showPagination={true}
            defaultPageSize={25}
            pageSizeOptionsOverride={[10, 25, 50, 100]}
            showSearch={false}
            showFilter={false}
            showToolbar={false}
            showColumns={false}
            showExport={false}
            hideReset={true}
            rowHeight={44}
            autoHeight={false}
            hideFooter={false}
            gridSx={{ 
              height: '100%',
              width: '100%',
              display: 'flex',
              flexDirection: 'column',
              // Hide toolbar container when showToolbar is false
              '& .atlas-table-toolbar-container': {
                display: 'none !important',
              },
              // Remove all borders - only show row dividers
              '& .MuiDataGrid-root': {
                border: 'none !important',
                display: 'flex',
                flexDirection: 'column',
                flex: 1,
                minHeight: 0,
                height: '100%',
                maxHeight: '100%',
                
              },
              '& .MuiDataGrid-main': {
                border: 'none !important',
                borderRadius: 0,
                flex: '1 1 0%',
                minHeight: 0,
                display: 'flex',
                flexDirection: 'column',
                
                position: 'relative',
              },
              '& .MuiDataGrid-columnHeaders': {
                flexShrink: 0,
              },
              '& .MuiDataGrid-virtualScroller': {
                border: 'none !important',
                flex: '1 1 0%',
                minHeight: 0,
                maxHeight: '100%',
                overflowX: 'hidden !important',
                overflowY: 'auto !important',
                position: 'relative',
              },
              // Ensure scrollbar is visible
              /* Use native browser scrollbars */
              '& .MuiDataGrid-virtualScrollerContent': {
                borderLeft: 'none !important',
                borderRight: 'none !important',
              },
              '& .MuiDataGrid-row': {
                border: 'none !important',
                borderBottom: 'none !important',
                borderTop: 'none !important',
                minHeight: '44px !important',
              },
              '& .MuiDataGrid-row .MuiDataGrid-cell': {
                borderLeft: 'none !important',
                borderRight: 'none !important',
                borderTop: 'none !important',
                borderBottom: '1px solid #dadada !important',
              },
              '& .MuiDataGrid-row:last-of-type .MuiDataGrid-cell': {
                borderBottom: '1px solid #dadada !important',
              },
              '& .MuiDataGrid-columnHeader': {
                border: 'none !important',
                borderBottom: '1px solid #dadada !important',
                backgroundColor: '#f3f3f3',
              },
              '& .MuiDataGrid-columnHeaders': {
                border: 'none !important',
                backgroundColor: '#f3f3f3',
              },
              '& .MuiDataGrid-filler': {
                borderLeft: 'none !important',
                borderRight: 'none !important',
              },
              // Ensure pagination footer is visible and doesn't shrink
              '& .MuiDataGrid-footerContainer': {
                display: 'flex !important',
                visibility: 'visible !important',
                opacity: '1 !important',
                borderTop: 'none !important',
                minHeight: '48px !important',
                height: '48px !important',
                maxHeight: '48px !important',
                flex: '0 0 48px',
                flexShrink: 0,
                flexGrow: 0,
                position: 'relative',
                zIndex: 10,
                padding: '8px 0',
                marginTop: 0,
                order: 999, // Ensure it's always last
              },
              '& .MuiDataGrid-pagination': {
                display: 'flex !important',
                visibility: 'visible !important',
                opacity: '1 !important',
                width: '100%',
              },
              '& .atlas-table-pagination-container': {
                display: 'flex !important',
                visibility: 'visible !important',
                opacity: '1 !important',
                width: '100%',
              },
            }}
            emptyStateTitle="No workflows found"
          />
        </Box> 
      </Box>
    </FAWErrorBoundary>
  );

  // Create breadcrumb-style title
  // Determine the label: snippetName > Edit Snippet > Add new snippet
  const getBreadcrumbLabel = () => {
    if (snippetName && snippetName.trim()) {
      return snippetName.trim();
    } else if (snippetId && snippetId !== 0) {
      return 'Edit Snippet';
    } else {
      return 'Add new snippet';
    }
  };

  const breadcrumbLabel = getBreadcrumbLabel();
  const hasSnippetName = snippetName && snippetName.trim();

  const drawerTitle = (
    <Box sx={{ 
      display: 'flex', 
      alignItems: 'center', 
      gap: 1,
      minWidth: 0, // Allow flex children to shrink
      overflow: 'hidden', // Prevent container overflow
      maxWidth: '100%', // Constrain to parent width
      flex: 1, // Take available space
    }}>
      <FAWTypography
        component="span"
        sx={{
          fontWeight: 400,
          fontSize: '18px',
          flexShrink: 0, // Don't shrink "Workflows"
          whiteSpace: 'nowrap',
        }}
      >
        Workflows
      </FAWTypography>
      {hasSnippetName && (
        <>
          <FAWTypography
            component="span"
            sx={{
              fontWeight: 400,
              fontSize: '18px',
              flexShrink: 0, // Don't shrink the separator
              whiteSpace: 'nowrap',
            }}
          >
            &gt;
          </FAWTypography>
          <FAWTooltip title={breadcrumbLabel}>
            <Box
              component="span"
              sx={{
                display: 'inline-block',
                minWidth: 0, // Allow to shrink
                maxWidth: 'calc(100% - 100px)', // Reserve space for "Workflows > " (approx 100px)
                overflow: 'hidden',
                flexShrink: 1, // Allow to shrink when needed
                verticalAlign: 'middle',
              }}
            >
              <FAWTypography
                component="span"
                sx={{
                  fontWeight: 400,
                  fontSize: '18px',
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  display: 'block',
                  maxWidth: '100%',
                }}
              >
                {breadcrumbLabel}
              </FAWTypography>
            </Box>
          </FAWTooltip>
        </>
      )}
    </Box>
  );

  return (
    <FAWDrawer
      open={true}
      onClose={handleDrawerClose}
      title={drawerTitle}
      width={800}
      anchor="right"
      showBackArrow={true}
      onBackClick={handleDrawerClose}
      actions={[
        {
          label: 'Cancel',
          text: 'Cancel',
          variant: 'outlined',
          onClick: handleDrawerClose,
          color: 'inherit',
          handlerType: 'custom'
        },
        {
          label: 'Save',
          text: 'Save',
          variant: 'contained',
          onClick: () => {
            // Apply the selection changes to the payload
            if (onAssociationsChange) {
              onAssociationsChange(selectedWorkflows);
            }
            handleDrawerClose();
          },
          color: 'primary',
          handlerType: 'custom'
        }
      ]}
      sx={{
        '& .MuiDrawer-paper': {
          minWidth: 700,
          maxWidth: 1000,
           // Prevent drawer paper from scrolling
        }
      }}
      contentSx={{
        // Prevent content area from scrolling
        display: 'flex',
        flexDirection: 'column',
        height: '100%'
      }}
    >
      {drawerContent}
    </FAWDrawer>
  );
};

export default WorkflowAssociationTable;