import React, { useState, useMemo } from 'react';
import { Box, Button } from '@mui/material';
import { Edit as EditIcon } from '@mui/icons-material';
import FAWTypography from '../../../FAWTypography';
// Keep FAWAgGrid for verification - will remove after UI testing
// import FAWAgGrid from '../../../FAWAgGrid';
import FAWTable from '../../../FAWTable/FAWTable';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import WorkflowAssociationTable from './WorkflowAssociationTable';
import NoResultsFound from '../../../shared/NoResultsFound';

/**
 * Workflow Associations Section Component
 * Handles the workflow associations tab content for snippets
 */
const WorkflowAssociationsSection = ({
  snippetId,
  snippetName = '',
  allWorkflowDefs,
  selectedWorkflows,
  onAssociationsChange
}) => {
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);

  // Prepare data for FAWTable - only show selected workflows
  const rows = useMemo(() => {
    const filtered = allWorkflowDefs
      .filter(workflow => selectedWorkflows.includes(workflow.Id || workflow.id))
      .map(workflow => ({
        id: workflow.Id || workflow.id,
        name: workflow.Name || workflow.name || 'Unnamed Workflow',
        description: workflow.Description || workflow.description || '',
        // Add any other workflow properties you need
        ...workflow
      }));
    return filtered;
  }, [allWorkflowDefs, selectedWorkflows]);

  // Column definitions for FAWTable - read-only display (name only)
  const columns = useMemo(() => [
    {
      field: 'name',
      headerName: 'Workflow Name',
      flex: 1,
      minWidth: 200,
      sortable: true,
      filterable: false,
      renderCell: (params) => {
        return (
          <FAWTypography 
            variant="body2" 
            sx={{ 
              fontWeight: 500,
              margin: 0
            }}
          >
            {params.value || 'Unnamed Workflow'}
          </FAWTypography>
        );
      }
    }
  ], []);

  // Prepare data for FAWAgGrid - only show selected workflows (OLD AG Grid code - kept for reference)
  const gridData = useMemo(() => {
    const filtered = allWorkflowDefs
      .filter(workflow => selectedWorkflows.includes(workflow.Id || workflow.id))
      .map(workflow => ({
        id: workflow.Id || workflow.id,
        name: workflow.Name || workflow.name,
        description: workflow.Description || workflow.description || '',
        // Add any other workflow properties you need
        ...workflow
      }));
    return filtered;
  }, [allWorkflowDefs, selectedWorkflows]);

  // Column definitions for FAWAgGrid - read-only display (name only) (OLD AG Grid code - kept for reference)
  const columnDefs = useMemo(() => [
    {
      field: 'name',
      headerName: 'Workflow Name',
      flex: 1,
      minWidth: 200,
      cellStyle: {
        padding: 'var(--ag-cell-vertical-padding, 8px) var(--ag-cell-horizontal-padding, 16px)',
        display: 'flex',
        alignItems: 'center'
      },
      cellRenderer: (params) => {
        return (
          <FAWTypography 
            variant="body2" 
            style={{ 
              fontWeight: 500,
              margin: 0
            }}
          >
            {params.value || 'Unnamed Workflow'}
          </FAWTypography>
        );
      }
    }
  ], []);

  const handleEditClick = () => {
    setIsDrawerOpen(true);
  };

  const handleDrawerClose = () => {
    setIsDrawerOpen(false);
  };

  const handleAssociationsChange = (newSelectedWorkflows) => {
    onAssociationsChange(newSelectedWorkflows);
  };
  
  return (
    <FAWErrorBoundary
      title="Workflow Associations Error"
      message="An error occurred while loading workflow associations. Please try again."
      showDetails={false}
    >
      <Box 
        className="workflow-associations-section-container"
        sx={{
          boxSizing: 'border-box',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--spacing-0, 0px)',
          alignItems: 'flex-start',
          position: 'relative',
          width: '100%',
          height: '100%'
        }}
      >
        {/* Applied in Workflows Section Header - Always visible */}
            <Box sx={{
              boxSizing: 'border-box',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--spacing-1, 8px)',
              alignItems: 'flex-start',
              position: 'relative',
              width: '100%',
              padding: '16px 0'
            }}>
          <Box sx={{
            boxSizing: 'border-box',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--spacing-0, 0px)',
            alignItems: 'center',
            overflow: 'hidden',
            width: '100%'
          }}>
            <Box sx={{
              boxSizing: 'border-box',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--spacing-1, 8px)',
              alignItems: 'flex-start',
              maxWidth: '1664px',
              minWidth: '320px',
              width: '100%'
            }}>
              <Box sx={{
                boxSizing: 'border-box',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--spacing-0, 0px)',
                alignItems: 'flex-start',
                justifyContent: 'center',
                width: '100%'
              }}>
                <Box sx={{
                  boxSizing: 'border-box',
                  display: 'flex',
                  gap: 'var(--spacing-0, 0px)',
                  alignItems: 'center',
                  maxWidth: '1920px',
                  width: '100%'
                }}>
                  <Box sx={{
                    boxSizing: 'border-box',
                    display: 'flex',
                    flex: '1 0 0',
                    flexDirection: 'column',
                    gap: 'var(--spacing-0_5, 4px)',
                    alignItems: 'flex-start',
                    minHeight: 0,
                    minWidth: 0,
                    overflow: 'hidden'
                  }}>
                    <FAWTypography sx={{
                      fontFamily: '"Plus Jakarta Sans", sans-serif',
                      fontWeight: 600,
                      fontSize: '18px',
                      lineHeight: '28px',
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      position: 'relative',
                      color: 'var(--color-type-default, #282e37)',
                      letterSpacing: '0.2px',
                      width: '100%',
                      whiteSpace: 'nowrap'
                    }}>
                      Applied in Workflows
                    </FAWTypography>
                  </Box>
                  <Box sx={{
                    boxSizing: 'border-box',
                    display: 'flex',
                    gap: 'var(--spacing-2, 16px)',
                    alignItems: 'center',
                    justifyContent: 'flex-end',
                    pl: 'var(--spacing-2, 16px)',
                    pr: 'var(--spacing-0, 0px)',
                    py: 'var(--spacing-0, 0px)',
                    position: 'relative'
                  }}>
                    <Button
                      variant="outlined"
                      startIcon={<EditIcon />}
                      onClick={handleEditClick}
                      sx={{
                        borderColor: 'var(--color-action-secondary-outline, #282e37)',
                        color: 'var(--color-action-secondary-outline, #282e37)',
                        fontFamily: '"Plus Jakarta Sans", sans-serif',
                        fontWeight: 600,
                        fontSize: '14px',
                        lineHeight: '20px',
                        textTransform: 'none',
                        px: 2,
                        py: 1,
                        '&:hover': {
                          borderColor: 'var(--color-action-secondary-outline-hover, #1a1d23)',
                          color: 'var(--color-action-secondary-outline-hover, #1a1d23)',
                          backgroundColor: 'rgba(40, 46, 55, 0.04)'
                        }
                      }}
                    >
                      Edit
                    </Button>
                  </Box>
                </Box>
              </Box>
            </Box>
          </Box>
        </Box>

        {/* Workflow List Table or Empty State */}
        {selectedWorkflows.length > 0 ? (
          <Box sx={{
            width: '100%',
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
            minHeight: 0
          }}>
            <Box className="workflow-associations-grid-container" sx={{ flex: 1, minHeight: 0 }}>
              <FAWTable
                rows={rows}
                columns={columns}
                showPagination={true}
                defaultPageSize={10}
                pageSizeOptionsOverride={[5, 10, 25, 50]}
                showSearch={false}
                showFilter={false}
                showToolbar={false}
                showColumns={false}
                showExport={false}
                hideReset={true}
                checkboxSelection={false}
                enableMultiSelect={false}
                hasDisableRowSelectionClick={true}
                rowHeight={44}
                maxHeight={600}
                minHeight={400}
                gridSx={{ height: '100%', width: '100%' }}
                emptyStateTitle="No workflows found"
              />

              {/* OLD FAWAgGrid - kept for verification, will remove after UI testing */}
              {/* <FAWAgGrid
                key={`workflow-grid-${Date.now()}`}
                rowData={gridData}
                columnDefs={columnDefs}
                pagination={true}
                paginationPageSize={10}
                paginationPageSizeSelector={[5, 10, 25, 50]}
                paginationAutoPageSize={false}
                onGridReady={() => {
                  // Grid ready
                }}
              /> */}
            </Box>
          </Box>
        ) : (
          /* No Content Empty State */
          <Box sx={{
            width: '100%',
            flex: '1 0 0',
            minHeight: 0,
            minWidth: 0,
            position: 'relative',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center'
          }}>
            <NoResultsFound
              title="No content"
              subtitle="Workflows where this snippet is added will be listed here"
              className="workflow-associations-empty-state"
            />
          </Box>
        )}

        {/* Workflow Selection Drawer */}
        {isDrawerOpen && (
          <WorkflowAssociationTable
            snippetId={snippetId}
            snippetName={snippetName}
            allWorkflowDefs={allWorkflowDefs}
            selectedWorkflows={selectedWorkflows}
            onAssociationsChange={handleAssociationsChange}
            onClose={handleDrawerClose}
          />
        )}
      </Box>
    </FAWErrorBoundary>
  );
};

export default WorkflowAssociationsSection;
