import React, {
  useState,
  useEffect,
  forwardRef,
  useImperativeHandle,
  useCallback,
} from "react";

import { Box, Alert } from "@mui/material";
import FAWSkeleton from "../../../FAWSkeleton";
import FAWLoader from "../../../FAWLoader";
import FAWInput from "../../../FAWInput";
import FAWTextarea from "../../../FAWTextarea";
import FAWDropdown from "../../../FAWDropdown";
import FAWCheckbox from "../../../FAWCheckbox";
import FAWToast from "../../../FAWToast";
import FAWErrorBoundary from "../../../errorHandling/FAWErrorBoundary";
import WorkflowAssociationsSection from "./WorkflowAssociationsSection";
import { snippetApi } from "../services/snippetApi";
import {
  validateSnippet,
  validateFormField,
} from "../../shared/utils/validation";
import { useDebouncedCallback } from "../../shared/hooks/useDebounce";

const SnippetForm = forwardRef(
  (
    {
      snippetId,
      onSave,
      onCancel,
      initialData,
      options: initialOptions,
      subcategoryOptionsByCategoryJson,
      allWorkflowDefs: propAllWorkflowDefs,
      saving: propSaving,
    },
    ref,
  ) => {
    const [formData, setFormData] = useState({
      Id: null, // Include Id field for updates
      Name: "",
      Description: "",
      CategoryCode: "",
      SubcategoryCode: "",
      IsActive: true, // Changed from Active to IsActive to match backend ViewModel
      LockId: 0,
      SubcategoryOptionsByCategoryJson: "",
      selectedWorkflows: [], // For workflow associations
    });

    // Use allWorkflowDefs from props (passed from .cshtml) or fallback to empty array
    const allWorkflowDefs = propAllWorkflowDefs || [];

    const [options, setOptions] = useState({
      categories: [],
      subcategories: [],
    });

    // Subcategory management state
    const [subcategoryLoading, setSubcategoryLoading] = useState(false);

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [fieldErrors, setFieldErrors] = useState({});
    const [toast, setToast] = useState({
      open: false,
      message: "",
      type: "info",
      duration: 3000,
    });

    // Enhanced form validation using Yup schemas
    const validateForm = async () => {
      try {
        // First validate with Yup schema
        const result = await validateSnippet(formData);
        const finalErrors = { ...result.fieldErrors };

        // Then validate name uniqueness if name is provided
        if (formData.Name && formData.Name.trim().length > 0) {
          // Don't validate if it's the same as initial data
          if (!initialData || initialData.Name !== formData.Name) {
            try {
              const nameCheckResult = await snippetApi.validateName(
                formData.Name,
                snippetId,
              );
              if (!nameCheckResult) {
                finalErrors.Name = "Error validating name";
                result.isValid = false;
              } else if (!nameCheckResult.isValid) {
                finalErrors.Name =
                  nameCheckResult.message ||
                  `Name [${formData.Name}] has been used.`;
                result.isValid = false;
              }
            } catch (err) {
              finalErrors.Name = "Error validating name";
              result.isValid = false;
            }
          }
        }

        // Set all field errors once after all validations complete
        setFieldErrors(finalErrors);
        return { ...result, fieldErrors: finalErrors };
      } catch (error) {
        console.error("Validation error:", error);
        const errorFields = { general: "Validation error occurred" };
        setFieldErrors(errorFields);
        return {
          isValid: false,
          fieldErrors: errorFields,
        };
      }
    };

    const isFormValid = async () => {
      try {
        setError(null); // Clear any previous errors

        // Add timeout to prevent hanging
        const timeoutPromise = new Promise((_, reject) => {
          setTimeout(() => reject(new Error("Validation timeout")), 10000);
        });

        const validationResult = await Promise.race([
          validateForm(),
          timeoutPromise,
        ]);

        return validationResult.isValid;
      } catch (error) {
        console.error("Form validation error:", error);
        if (error.message === "Validation timeout") {
          setError("Validation timed out. Please try again.");
        } else {
          setError("Validation failed due to an unexpected error");
        }
        return false;
      }
    };

    // Clear field error when field value changes
    const clearFieldError = (fieldName) => {
      if (fieldErrors[fieldName]) {
        const newErrors = { ...fieldErrors };
        delete newErrors[fieldName];
        setFieldErrors(newErrors);
      }
    };

    // Debounced field validation using Yup
    const validateFieldDebounced = useDebouncedCallback(
      async (fieldName, value) => {
        try {
          const result = await validateFormField("snippet", fieldName, value);
          if (!result.isValid) {
            setFieldErrors((prev) => ({ ...prev, [fieldName]: result.error }));
          } else {
            clearFieldError(fieldName);
          }
        } catch (error) {
          console.error("Field validation error:", error);
        }
      },
      1000,
    ); // 1000ms delay

    // Cleanup effect to reset validation state
    useEffect(() => {
      return () => {
        setError(null);
        setFieldErrors({});
      };
    }, []);

    // Function to focus on first error field
    const focusFirstError = useCallback(() => {
      const errorFields = Object.keys(fieldErrors);
      if (errorFields.length > 0) {
        const firstErrorField = errorFields[0];
        const element = document.getElementById(
          `snippet-${firstErrorField.toLowerCase()}`,
        );
        if (element) {
          element.scrollIntoView({ behavior: "smooth", block: "center" });
          element.focus();
        }
      }
    }, [fieldErrors]);

    // Expose methods to parent component
    useImperativeHandle(ref, () => ({
      getFormData: () => formData,
      isFormValid,
      focusFirstError,
    }));

    // Load data when component mounts or props change
    useEffect(() => {
      loadData();
    }, [snippetId, initialData, initialOptions, allWorkflowDefs]);

    // Watch for category changes and load subcategories automatically
    useEffect(() => {
      if (formData.CategoryCode) {
        updateSubcategories(formData.CategoryCode);
      } else {
        setOptions((prev) => ({ ...prev, subcategories: [] }));
      }
    }, [formData.CategoryCode]);

    // Load subcategories on mount if category is already selected
    useEffect(() => {
      if (formData.CategoryCode && !subcategoryLoading) {
        updateSubcategories(formData.CategoryCode);
      }
    }, []); // Empty dependency array = run only on mount

    const loadData = () => {
      setLoading(true);
      setError(null);

      try {
        // Set options from props
        if (initialOptions) {
          setOptions(initialOptions);
        }

        // Set initial form data if provided with safety checks
        if (initialData && typeof initialData === "object") {
          // Parse selected workflows from WorkFlowSnippetIds (from API response - source of truth)
          let selectedWorkflows = [];
          if (
            initialData.WorkFlowSnippetIds &&
            initialData.WorkFlowSnippetIds.trim()
          ) {
            selectedWorkflows = initialData.WorkFlowSnippetIds.split(",")
              .map((id) => parseInt(id.trim()))
              .filter((id) => !isNaN(id));
          }

          setFormData((prev) => ({
            ...prev,
            Id: initialData.Id || null, // Include the Id field for updates
            Name: initialData.Name || "",
            Description: initialData.Description || "",
            CategoryCode: initialData.CategoryCode || "",
            SubcategoryCode: initialData.SubcategoryCode || "",
            IsActive:
              initialData.IsActive !== undefined
                ? initialData.IsActive
                : initialData.Active !== undefined
                  ? initialData.Active
                  : true, // Support both IsActive and Active for backward compatibility
            LockId: initialData.LockId || 0,
            SubcategoryOptionsByCategoryJson:
              initialData.SubcategoryOptionsByCategoryJson || "",
            selectedWorkflows: selectedWorkflows, // Use parsed workflow IDs from snippet data
          }));

          // Load subcategories for the selected category
          if (initialData.CategoryCode) {
            updateSubcategories(initialData.CategoryCode);
          }
        }
      } catch (err) {
        console.error("Error loading data:", err);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    const handleInputChange = (field, value) => {
      try {
        // Ensure value is not undefined or null
        const safeValue = value !== undefined && value !== null ? value : "";

        setFormData((prev) => ({ ...prev, [field]: safeValue }));

        // Validate name if it's the name field
        if (field === "Name") {
          validateFieldDebounced(field, safeValue);
        }

        // Update subcategories when category changes
        if (field === "CategoryCode") {
          updateSubcategories(safeValue);
          // Clear subcategory selection when category changes
          setFormData((prev) => ({ ...prev, SubcategoryCode: "" }));
        }
      } catch (error) {
        console.error("Error in handleInputChange:", error);
        setError("Error updating form field");
      }
    };

    const updateSubcategories = async (categoryCode) => {
      if (!categoryCode) {
        setOptions((prev) => ({ ...prev, subcategories: [] }));
        return;
      }

      setSubcategoryLoading(true);
      try {
        // Make API call to get subcategories for the selected category
        const subcategories = await snippetApi.getSubcategories(categoryCode);
        setOptions((prev) => ({ ...prev, subcategories }));
      } catch (error) {
        console.error("Error loading subcategories:", error);
        setOptions((prev) => ({ ...prev, subcategories: [] }));
      } finally {
        setSubcategoryLoading(false);
      }
    };

    const handleToastClose = () => {
      setToast({ open: false, message: "", type: "info", duration: 3000 });
    };

    if (loading) {
      return (
        <Box sx={{ p: 3 }}>
          <FAWSkeleton variant="form" />
        </Box>
      );
    }

    return (
      <FAWErrorBoundary
        title="Form Error"
        message="An error occurred while rendering the snippet form. Please try again."
        showDetails={false}
        onError={(error, errorInfo) => {
          console.error("SnippetForm Error:", error, errorInfo);
        }}
      >
        <Box
          className="snippet-form-container"
          sx={{ p: 3, position: "relative" }}
        >
          {/* Error Alert */}
          {error && (
            <Alert
              className="snippet-form-error-alert"
              severity="error"
              sx={{ mb: 2 }}
            >
              {error}
            </Alert>
          )}

          <form className="snippet-form" onSubmit={(e) => e.preventDefault()}>
            <Box
              className="snippet-form-fields"
              sx={{ display: "flex", flexDirection: "column", gap: 3 }}
            >
              {/* Name Input */}
              <FAWInput
                className="snippet-form-name-input"
                id="snippet-name"
                label="Name"
                placeholder="Enter snippet name"
                value={formData.Name}
                onChange={(e) => handleInputChange("Name", e.target.value)}
                error={!!fieldErrors.Name}
                helperText={fieldErrors.Name}
                variant="outlined"
                fullWidth
                required
                labelSx={{
                  fontSize: "14px",
                  fontWeight: 500,
                }}
                sx={{
                  "& .MuiOutlinedInput-root": { backgroundColor: "#ffffff" },
                }}
              />

              {/* Description Textarea */}
              <FAWTextarea
                className="snippet-form-description-textarea"
                id="snippet-description"
                label="Description"
                placeholder="Enter snippet description"
                value={formData.Description}
                onChange={(e) =>
                  handleInputChange("Description", e.target.value)
                }
                error={!!fieldErrors.Description}
                helperText={fieldErrors.Description}
                rows={3}
                variant="outlined"
                fullWidth
                sx={{
                  "& .MuiOutlinedInput-root": { backgroundColor: "#ffffff" },
                }}
              />

              {/* Category Dropdown */}
              <FAWDropdown
                className="snippet-form-category-dropdown"
                id="snippet-category"
                label="Category"
                value={formData.CategoryCode || ""}
                onChange={(option) =>
                  handleInputChange("CategoryCode", option?.value || "")
                }
                options={options.categories}
                loading={loading && options.categories.length === 0}
                error={!!fieldErrors.CategoryCode}
                helperText={fieldErrors.CategoryCode}
                fullWidth
              />

              {/* Subcategory Dropdown */}
              <FAWDropdown
                className="snippet-form-subcategory-dropdown"
                id="snippet-subcategory"
                label="Subcategory"
                value={formData.SubcategoryCode || ""}
                onChange={(option) =>
                  handleInputChange("SubcategoryCode", option?.value || "")
                }
                options={options.subcategories}
                disabled={!formData.CategoryCode || subcategoryLoading}
                loading={subcategoryLoading}
                error={!!fieldErrors.SubcategoryCode}
                helperText={fieldErrors.SubcategoryCode}
                fullWidth
                placeholder={
                  !formData.CategoryCode
                    ? "Select category before selecting subcategory"
                    : subcategoryLoading
                      ? "Loading subcategories..."
                      : options.subcategories.length === 0
                        ? "No subcategories available under selected category"
                        : "-- SELECT --"
                }
              />

              {/* Active Checkbox */}
              <FAWCheckbox
                className="snippet-form-active-checkbox"
                id="snippet-active"
                label="Active"
                checked={formData.IsActive}
                onChange={(e) =>
                  handleInputChange("IsActive", e.target.checked)
                }
                size="medium"
              />
            </Box>
          </form>

          {/* Workflow Associations Section - Show for both create and update */}
          <Box
            className="snippet-form-associations-section"
            sx={{ mt: 3, pt: 3, borderTop: "1px solid #e0e0e0" }}
          >
            <WorkflowAssociationsSection
              snippetId={snippetId}
              snippetName={formData.Name || ""}
              allWorkflowDefs={allWorkflowDefs}
              selectedWorkflows={formData.selectedWorkflows || []}
              onAssociationsChange={(selectedIds) => {
                setFormData((prev) => {
                  const newData = {
                    ...prev,
                    selectedWorkflows: selectedIds,
                  };
                  return newData;
                });
              }}
            />
          </Box>

          {/* Toast for notifications */}
          <FAWToast
            open={toast.open}
            message={toast.message}
            type={toast.type}
            duration={toast.duration}
            onClose={handleToastClose}
          />

          {/* Saving Loader Overlay */}
          {propSaving && (
            <Box
              sx={{
                position: "absolute",
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                backgroundColor: "rgba(255, 255, 255, 0.8)",
                backdropFilter: "blur(2px)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                zIndex: 1000,
              }}
            >
              <FAWLoader
                size={40}
                label={
                  snippetId ? "Updating snippet..." : "Creating snippet..."
                }
                inline={false}
              />
            </Box>
          )}
        </Box>
      </FAWErrorBoundary>
    );
  },
);

SnippetForm.displayName = "SnippetForm";

export default SnippetForm;
