import { useCallback } from 'react';
import { snippetApi } from '../services/snippetApi';
import { showToast } from '../../../shared/ToastManager';
import { getWarningMessage } from '../../../shared/utils/formChangeDetection';
import { CANCEL_MESSAGES, CANCEL_ERROR_MESSAGES } from '../../constants/cancelMessages';
import { logger } from '../../../shared/utils/logger';

// Toast notification duration (30 seconds)
const TOAST_DURATION = 30000;

/**
 * Custom hook for managing SnippetManager event handlers
 * Extracts all handler logic to make the component more modular
 */
export const useSnippetWorkflowDefinitionHandlers = ({
  snippetId,
  currentSnippetId,
  setCurrentSnippetId,
  taskId,
  onSuccess,
  onCancel,
  formRef,
  taskDetailRef,
  saving,
  setSaving,
  setValidating,
  setDrawerOpen,
  setError,
  setSelectedWorkflows,
  setCurrentTask,
  setTaskDetailLoading,
  setTaskDetail,
  setTaskFetchError,
  setFormChanged,
  setSearchUDFModalOpen,
  setAdhocSettingsModalOpen,
  setPreconditionsModalOpen,
  setInsertSnippetModalOpen,
  setSnippetTreeData,
  setConfirmationDialog,
  currentTask,
  taskDetail,
  formChanged,
  onCurrentTaskClear,
  fetchTreeData,
  setTreeDataError,
  setTreeLoading,
  setLoading,
  setInitialData,
  setFullPageLoader
}) => {

  const handleSaveClick = useCallback(async () => {
    if (!formRef.current) {
      showToast.error('Form not available', TOAST_DURATION);
      return;
    }

    const formData = formRef.current.getFormData ? formRef.current.getFormData() : null;
    if (!formData) {
      showToast.error('Form data not available', TOAST_DURATION);
      return;
    }

    try {
      setValidating(true);
      const isFormValid = await formRef.current.isFormValid();
      if (!isFormValid) {
        showToast.error('Please fix validation errors before saving', TOAST_DURATION);
        if (formRef.current && formRef.current.focusFirstError) {
          formRef.current.focusFirstError();
        }
        return;
      }
    } catch (validationError) {
      showToast.error(validationError.message || 'Form validation failed', TOAST_DURATION);
      return;
    } finally {
      setValidating(false);
    }

    setSaving(true);
    setError(null);
    setFullPageLoader({
      open: true,
      message: 'Saving snippet...'
    });

    try {
      const { selectedWorkflows, ...snippetData } = formData;
      const mappedFormData = {
        ...snippetData,
        WorkFlowSnippetIds: selectedWorkflows && selectedWorkflows.length > 0 
          ? selectedWorkflows.join(',') 
          : ''
      };
      
      const result = await snippetApi.saveSnippet(mappedFormData);
      
      if (result.success) {
        showToast.success(result.message || 'Snippet saved successfully!', TOAST_DURATION);
        
        setDrawerOpen(false);
        
        const newSnippetId = result.data?.id || result.snippetId;
        
        if (!currentSnippetId && newSnippetId) {
          const currentUrl = new URL(window.location.href);
          currentUrl.searchParams.set('id', newSnippetId);
          window.location.href = currentUrl.toString();
          return;
        }
        
        // Update initialData with the saved formData (no need to fetch again)
        if (currentSnippetId && formData) {
          setInitialData({
            ...formData,
            Id: currentSnippetId,
            WorkFlowSnippetIds: mappedFormData.WorkFlowSnippetIds
          });
        }
        
        if (onSuccess) {
          onSuccess(result);
        }
      } else {
        showToast.error(result.message || 'Failed to save snippet', TOAST_DURATION);
      }
    } catch (error) {
      const errorMessage = error.message || 'Failed to save snippet';
      showToast.error(errorMessage, TOAST_DURATION);
    } finally {
      setSaving(false);
      setFullPageLoader(prev => ({ ...prev, open: false }));
    }
  }, [formRef, setSaving, setValidating, setDrawerOpen, setError, onSuccess, currentSnippetId, setCurrentSnippetId, setLoading, setInitialData, fetchTreeData, setFullPageLoader]);

  const handleCancel = useCallback(() => {
    if (currentSnippetId && currentSnippetId > 0) {
      setDrawerOpen(false);
      setError(null);
    } else {
      if (onCancel) {
        onCancel();
      } else {
        window.location.href = '/WorkflowTaskDefSnippet';
      }
    }
  }, [currentSnippetId, setDrawerOpen, setError, onCancel]);

  const handleCloseDrawer = useCallback(() => {
    if (currentSnippetId && currentSnippetId > 0) {
      setDrawerOpen(false);
      setError(null);
    } else {
      handleCancel();
    }
  }, [currentSnippetId, setDrawerOpen, setError, handleCancel]);

  const handleToastClose = useCallback(() => {
  }, []);

  const handleTabChange = useCallback((event, newValue) => {
  }, []);

  const showConfirmationDialog = useCallback((title, message, onConfirm, options = {}) => {
    setConfirmationDialog({
      open: true,
      title,
      message,
      onConfirm: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
        onConfirm();
      },
      onCancel: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
      },
      confirmText: options.confirmText || 'Yes',
      cancelText: options.cancelText || 'No',
      severity: options.severity || 'warning'
    });
  }, [setConfirmationDialog]);

  const handleWorkflowAssociationsChange = useCallback(async (workflowIds) => {
    if (!snippetId) {
      return;
    }

    try {
      setSaving(true);
      const result = await snippetApi.saveWorkflowAssociations(currentSnippetId, workflowIds);
      
      if (result.success) {
        setSelectedWorkflows(workflowIds);
        showToast.success('Workflow associations updated successfully', TOAST_DURATION);
      } else {
        showToast.error(result.message || 'Failed to update workflow associations', TOAST_DURATION);
      }
    } catch (error) {
      showToast.error('Failed to update workflow associations', TOAST_DURATION);
    } finally {
      setSaving(false);
    }
  }, [snippetId, setSaving, setSelectedWorkflows]);

  const handleTreeChange = useCallback((treeData) => {
    setSnippetTreeData(treeData);
  }, [setSnippetTreeData]);

  const handleNodeSelect = useCallback(async (node, options = {}) => {
    if (!node || !node.id) {
      setCurrentTask(null);
      setTaskDetail(null);
      return;
    }

    const { skipConfirmation = false } = options;

    // If skipConfirmation is true, directly select the node without checking for unsaved changes
    if (skipConfirmation) {
      selectNode(node);
      return;
    }

    const isNew = taskDetailRef?.current?.isNewlyCreated;
    
    let hasChanges = false;
    if (taskDetailRef?.current?.checkForChanges) {
      hasChanges = taskDetailRef.current.checkForChanges();
    } else {
      hasChanges = formChanged;
    }

    if ((isNew || hasChanges) && currentTask) {
      const warningMessage = getWarningMessage(isNew, hasChanges);
      
      showConfirmationDialog(
        warningMessage?.title || 'Unsaved Changes',
        warningMessage?.message || 'Changes were made, do you want to continue without saving?',
        () => {
          selectNode(node);
        },
        {
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: warningMessage?.severity || 'warning'
        }
      );
      return;
    }

    if (currentTask && taskDetail && taskDetail.NewlyCreated) {
      showConfirmationDialog(
        'New Task Not Saved',
        'The new task definition has not yet been saved. Any changes will be lost and the element removed by canceling. Do you want to continue without saving?',
        () => {
          selectNode(node);
        },
        {
          confirmText: 'Continue',
          cancelText: 'Cancel',
          severity: 'error'
        }
      );
      return;
    }

    selectNode(node);
  }, [currentSnippetId, formChanged, currentTask, taskDetail, showConfirmationDialog, taskDetailRef, selectNode]);

  const selectNode = useCallback(async (node) => {
    setCurrentTask(node);
    setTaskDetailLoading(true);
    setTaskDetail(null);
    setFormChanged(false);
    setTaskFetchError(null);

    try {
      const taskDetailData = await snippetApi.getTaskDetail(currentSnippetId, node.id);
      
      if (!taskDetailData?.success) {
        setTaskDetail(null);
        setTaskDetailLoading(false);
        setTaskFetchError(taskDetailData?.message || 'Failed to load task details');
        showToast.error(taskDetailData?.message || 'Failed to load task details', TOAST_DURATION);
        return;
      }
      
      const receivedId = taskDetailData?.data?.Id || taskDetailData?.data?.id;
      const expectedId = node.id;
      const idMatches = String(receivedId) === String(expectedId);
      
      if (taskDetailData?.data && idMatches) {
        setTaskDetail(taskDetailData.data);
        setTaskFetchError(null);
      } else {
        setTaskDetail(null);
      }
    } catch (err) {
      showToast.error('Failed to load task details', TOAST_DURATION);
      setTaskDetail(null);
    } finally {
      setTaskDetailLoading(false);
    }
  }, [currentSnippetId, setCurrentTask, setTaskDetailLoading, setTaskDetail, setTaskFetchError, setError]);

  const handleTreeAction = useCallback((actionObj) => {
    switch (actionObj.actionType) {
      case 'remove':
        if (!actionObj.node || !actionObj.node.id) {
          showToast.error('Invalid task selected for removal');
          return;
        }
        
        showConfirmationDialog(
          'Remove Task',
          'Are you sure you want to remove the item from the workflow?',
          async () => {
            try {
              setSaving(true);
              const result = await snippetApi.removeTask(currentSnippetId, actionObj.node.id);
              if (result.success) {
                showToast.success('The task has been removed.');
                await fetchTreeData();
                if (currentTask && currentTask.id === actionObj.node.id && onCurrentTaskClear) {
                  onCurrentTaskClear();
                }
              } else {
                showToast.error(result.message || 'Failed to remove task');
              }
            } catch (error) {
              showToast.error('Failed to remove task');
            } finally {
              setSaving(false);
            }
          },
          {
            confirmText: 'Remove',
            cancelText: 'Cancel',
            severity: 'error'
          }
        );
        break;
      case 'moveUp':
        handleMoveTask(actionObj.node.id, true);
        break;
      case 'moveDown':
        handleMoveTask(actionObj.node.id, false);
        break;
      case 'moveToSection':
        handleMoveToSection(actionObj.node.id, actionObj.targetSectionId);
        break;
      case 'managePredecessors':
        handleManagePredecessors(actionObj.node.id);
        break;
      default:
        break;
    }
  }, [snippetId, showConfirmationDialog, setSaving, setSnippetTreeData, setCurrentTask, setTaskDetail, currentTask]);

  const handleMoveTask = useCallback(async (taskId, isUp) => {
    try {
      setSaving(true);
      const result = await snippetApi.moveTask(currentSnippetId, taskId, isUp);
      if (result.success) {
        showToast.success('Task moved successfully');
        await fetchTreeData();
      } else {
        showToast.error(result.message || 'Failed to move task');
      }
    } catch (error) {
      showToast.error('Failed to move task');
    } finally {
      setSaving(false);
    }
  }, [snippetId, setSaving, setSnippetTreeData]);

  const handleMoveToSection = useCallback(async (taskId, targetSectionId) => {
    try {
      setSaving(true);
      const result = await snippetApi.moveTaskToSection(currentSnippetId, taskId, targetSectionId);
      if (result.success) {
        showToast.success('Task moved to section successfully');
        await fetchTreeData();
      } else {
        showToast.error(result.message || 'Failed to move task to section');
      }
    } catch (error) {
      showToast.error('Failed to move task to section');
    } finally {
      setSaving(false);
    }
  }, [snippetId, setSaving, setSnippetTreeData]);

  const handleManagePredecessors = useCallback((taskId) => {
    showToast.info('Manage predecessors functionality not yet implemented');
  }, []);

  const handleTreeError = useCallback((error) => {
    showToast.error(error.message || 'Tree operation failed');
  }, []);

  const handleTaskSave = useCallback(async (taskData, currentTask) => {
    if (!snippetId || !currentTask?.id) {
      showToast.error('Cannot save task');
      return;
    }

    try {
      setSaving(true);
      const result = await snippetApi.saveTaskDetail(taskData);
      
      if (result.success) {
        showToast.success('Task saved successfully');
        setFormChanged(false);
        const updatedTaskDetail = await snippetApi.getTaskDetail(currentSnippetId, currentTask.id);
        if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
          setTaskDetail(updatedTaskDetail.data);
        }
        
        // Refresh tree data to reflect name changes in the left panel
        if (fetchTreeData) {
          await fetchTreeData();
        }
      } else {
        showToast.error(result.message || 'Failed to save task');
      }
    } catch (error) {
      showToast.error('Failed to save task');
    } finally {
      setSaving(false);
    }
  }, [snippetId, setSaving, setFormChanged, setTaskDetail, fetchTreeData, currentSnippetId]);

  /**
   * Handles task cancellation with change detection and confirmation
   * @param {Object} currentTask - The task to cancel
   * @param {number|string} currentTask.id - Task ID
   * @param {boolean} [currentTask.NewlyCreated] - Whether task is newly created
   * @param {boolean} [currentTask.IsNewlyCreated] - Alternative newly created flag (backend inconsistency)
   * @returns {Promise<void>}
   */
  const handleTaskCancel = useCallback(async (currentTask) => {
    logger.debug('handleTaskCancel invoked', { 
      taskId: currentTask?.id,
      snippetId: currentSnippetId,
      hasTaskDetailRef: !!taskDetailRef?.current
    });
    
    try {
      // Validate inputs
      if (!currentSnippetId || !currentTask?.id) {
        logger.error('Invalid parameters for cancelTask', {
          currentSnippetId,
          taskId: currentTask?.id
        });
        showToast.error(CANCEL_ERROR_MESSAGES.INVALID_PARAMS);
        
        // Close drawer to unblock user
        setTaskDetail(null);
        setCurrentTask(null);
        setFormChanged(false);
        return;
      }
      
      // Check if task is newly created (handle backend property inconsistency)
      const isNewlyCreated = currentTask?.NewlyCreated === true || currentTask?.IsNewlyCreated === true;
      
      // Check for unsaved changes using the child component's checkForChanges method
      let hasChanges = false;
      if (taskDetailRef?.current?.checkForChanges) {
        hasChanges = taskDetailRef.current.checkForChanges();
        logger.debug('Change detection result', { hasChanges, isNewlyCreated });
      } else {
        logger.warn('checkForChanges method not available on taskDetailRef');
      }
      
      // Show confirmation if task is newly created OR has unsaved changes
      if (isNewlyCreated || hasChanges) {
        const messages = isNewlyCreated 
          ? CANCEL_MESSAGES.NEWLY_CREATED 
          : CANCEL_MESSAGES.HAS_CHANGES;
        
        logger.debug('Showing confirmation dialog', { type: isNewlyCreated ? 'newly_created' : 'has_changes' });
        
        showConfirmationDialog(
          messages.title,
          messages.message,
          async () => {
            logger.debug('User confirmed cancel action');
            
            try {
              if (isNewlyCreated) {
                // Delete newly created task that was never saved
                await snippetApi.cancelTask(currentSnippetId, currentTask.id, true);
                logger.info('Newly created task deleted, reloading page');
                window.location.reload();
              } else {
                // Revert changes for existing task
                await snippetApi.cancelTask(currentSnippetId, currentTask.id, false);
                logger.info('Task changes reverted successfully');
                
                // Close the task detail drawer
                setTaskDetail(null);
                setCurrentTask(null);
                setFormChanged(false);
              }
            } catch (apiError) {
              logger.error('API call failed during cancel', apiError);
              showToast.error(CANCEL_ERROR_MESSAGES.API_FAILED);
              
              // Close drawer anyway to unblock user
              setTaskDetail(null);
              setCurrentTask(null);
              setFormChanged(false);
            }
          },
          {
            confirmText: messages.confirmText,
            cancelText: messages.cancelText
          }
        );
      } else {
        logger.debug('No changes detected, closing drawer immediately');
        // No changes, just close the task detail drawer
        setTaskDetail(null);
        setCurrentTask(null);
        setFormChanged(false);
      }
    } catch (error) {
      logger.error('Unexpected error in handleTaskCancel', error);
      showToast.error(CANCEL_ERROR_MESSAGES.GENERIC);
      
      // Always close drawer to prevent user from being stuck
      setTaskDetail(null);
      setCurrentTask(null);
      setFormChanged(false);
    }
  }, [currentSnippetId, setTaskDetail, setCurrentTask, setFormChanged, taskDetailRef, showConfirmationDialog]);

  const handleTaskSettingsSave = useCallback(async (taskSettingsData) => {
    if (saving) {
      return { success: false, message: 'Save already in progress' };
    }
    
    try {
      setSaving(true);
      const { snippetApi } = await import('../services/snippetApi');
      const result = await snippetApi.saveTaskDetail(taskSettingsData, true);
      
      if (result.success) {
        if (taskSettingsData?.Id && snippetId) {
          try {
            const updatedTaskDetail = await snippetApi.getTaskDetail(currentSnippetId, taskSettingsData.Id);
            if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
              if (setTaskDetail) {
                setTaskDetail(updatedTaskDetail.data);
              }
            }
          } catch (refreshError) {
          }
        }
      }
      
      return result;
    } catch (error) {
      showToast.error('Failed to save task settings', TOAST_DURATION);
      throw error;
    } finally {
      setSaving(false);
    }
  }, [saving, setSaving, snippetId, setTaskDetail]);

  const handleSearchUDFClose = useCallback(() => {
    setSearchUDFModalOpen(false);
  }, [setSearchUDFModalOpen]);

  const handleAdhocSettingsOpen = useCallback(() => {
    setAdhocSettingsModalOpen(true);
  }, [setAdhocSettingsModalOpen]);

  const handleAdhocSettingsClose = useCallback(() => {
    setAdhocSettingsModalOpen(false);
  }, [setAdhocSettingsModalOpen]);

  const handleAdhocSettingsSave = useCallback(async (settingsData) => {
    try {
      setSaving(true);
      showToast.success('Ad-hoc settings saved successfully', TOAST_DURATION);
      setAdhocSettingsModalOpen(false);
    } catch (error) {
      showToast.error('Failed to save adhoc settings', TOAST_DURATION);
    } finally {
      setSaving(false);
    }
  }, [setSaving, setAdhocSettingsModalOpen]);

  const handleSuccess = useCallback((message) => {
    showToast.success(message, TOAST_DURATION);
  }, []);

  const handleTreeDataRefresh = useCallback(async () => {
    if (!currentSnippetId || currentSnippetId === 0) {
      return [];
    }
    
    return await fetchTreeData();
  }, [currentSnippetId, fetchTreeData]);

  return {
    handleSaveClick,
    handleTaskSettingsSave,
    handleCancel,
    handleCloseDrawer,
    handleToastClose,
    handleTabChange,
    handleWorkflowAssociationsChange,
    handleTreeChange,
    handleNodeSelect,
    handleTreeAction,
    handleTreeError,
    handleTaskSave,
    handleTaskCancel,
    handleSearchUDFClose,
    handleAdhocSettingsOpen,
    handleAdhocSettingsClose,
    handleAdhocSettingsSave,
    handleSuccess,
    handleTreeDataRefresh,
    showConfirmationDialog
  };
};
