import React, { useState, useEffect, useMemo, useCallback, useImperativeHandle, useRef } from 'react';
import {
  Box,
  Grid, 
  Alert,
  Chip
} from '@mui/material';
import { isEqual, cloneDeep, omit } from 'lodash';
import { hasFormChangesByOmit, isNewlyCreated, getWarningMessage } from '../../../shared/utils/formChangeDetection';
import FAWButton from '../../../FAWButton';
import '../../css/workflow.css';
import FAWTypography from '../../../FAWTypography';
import { showToast } from '../../../shared/ToastManager';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import { validateWorkflowTaskDefinition } from '../../workflowdefinition/utils/workflowTaskValidation';

// Import shared components
import BasicTaskFields from '../../shared/components/BasicTaskFields';
import { 
  ActionTask, 
  NotificationTask, 
  CloseTask,
  SectionTask,
  StepTask,
  EditTask,
  ApproveTask,
  ReviewTask,
  RouteToTask,
  GoToTask,
  IfTask
} from '../../shared/components/taskTypes';

// Import shared utilities
import { 
  initializeFormData,
  validateForm,
  hasRequiredUDFs,
  areRequiredUDFsFilled,
  getTaskTypeFlags
} from '../../shared/utils';

/**
 * Snippet Task Detail Component
 * Renders the full task detail form for snippet tasks
 * Based on WorkflowTaskDetail from workflow definition
 */
const SnippetTaskDetail = React.forwardRef(({ 
  taskDetail, 
  loading, 
  onSave, 
  onCancel, 
  readOnly = false,
  snippetId,
  taskId,
  onFormChange,
  onTaskDetailUpdate
}, ref) => {
  const [formData, setFormData] = useState({});
  const [originalFormData, setOriginalFormData] = useState(null);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState(null);
  const [fieldErrors, setFieldErrors] = useState({});
  const ifTaskRef = useRef(null);

  // On-demand change detection - only compute when needed
  const [formChanged, setFormChanged] = useState(false);
  
  // Function to check for changes only when called
  const checkForChanges = useCallback(() => {
    if (!formData || !originalFormData) {
      setFormChanged(false);
      return false;
    }
    
    const hasChanges = hasFormChangesByOmit(formData, originalFormData);
    setFormChanged(hasChanges);
    
    // Notify parent component
    if (onFormChange) {
      onFormChange(hasChanges);
    }
    
    return hasChanges;
  }, [formData, originalFormData, onFormChange]);

  // Track the last processed task ID to prevent unnecessary resets
  const [lastProcessedTaskId, setLastProcessedTaskId] = useState(null);

  // Update form data when taskDetail changes
  useEffect(() => {
    if (taskDetail && taskDetail.Id !== lastProcessedTaskId) {
      const initializedData = initializeFormData(taskDetail);
      
      // Always update form data when taskDetail changes (new task selected)
      setFormData(initializedData);
      setOriginalFormData(cloneDeep(initializedData));
      
      // Reset form changed state immediately for new task
      setFormChanged(false);
      
      if (onFormChange) {
        onFormChange(false);
      }
      
      // Update the last processed task ID
      setLastProcessedTaskId(taskDetail.Id);
    }
  }, [taskDetail?.Id, onFormChange, lastProcessedTaskId]);



  // No automatic change detection - only when explicitly called

  // Expose methods to parent component via ref
  useImperativeHandle(ref, () => ({
    checkForChanges,
    formChanged,
    formData,
    originalFormData,
    isNewlyCreated: isNewlyCreated(formData)
  }), [checkForChanges, formChanged, formData, originalFormData]);

  // Handle field changes
  const handleFieldChange = (field, value) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    
    // No automatic change detection - only when explicitly needed
    // Note: Errors are only cleared during final save operation
  };

  const validateFormData = async (isCompletingTask = false) => {
    try {
      // Only validate UDFs when completing the task (matches legacy behavior)
      const result = await validateForm(formData, () => areRequiredUDFsFilled(formData, isCompletingTask));
      
      if (!result.isValid) {
        let firstError = 'Validation failed';
        if (result.fieldErrors) {
          const errorKeys = Object.keys(result.fieldErrors);
          if (errorKeys.length > 0) {
            firstError = result.fieldErrors[errorKeys[0]];
          }
        } else if (result.errors && result.errors.length > 0) {
          firstError = result.errors[0];
        }
        
        setError(firstError);
        return false;
      }
      setError(null);
      return true;
    } catch (error) {
      setError('Validation error occurred');
      return false;
    }
  };

  // Handle save
  const handleSave = async () => {
    // Note: Regular saves don't validate UDFs (matches legacy behavior)
    // UDFs are only validated when completing tasks (isCompletingTask = true)
    const isValid = await validateFormData(false); // false = not completing task
    if (!isValid) {
      return;
    }
    
    setSaving(true);
    setError(null);
    
    try {
      if (!onSave) return;
      const result = await onSave(formData);
      
      // If save was successful, fetch latest task data and update originalFormData
      if (result?.success && snippetId && taskId && onTaskDetailUpdate) {
        try {
          const { snippetApi } = await import('../services/snippetApi');
          const updatedTaskDetail = await snippetApi.getTaskDetail(snippetId, taskId);
          if (updatedTaskDetail?.success && updatedTaskDetail?.data) {
            // Update parent component with refreshed data
            onTaskDetailUpdate(updatedTaskDetail.data);
            
            // Process the refreshed data through initializeFormData to get normalized form data
            // This ensures originalFormData matches what the server actually saved
            const refreshedFormData = initializeFormData(updatedTaskDetail.data);
            setOriginalFormData(cloneDeep(refreshedFormData));
            
            // Also update current formData to match server response (in case server modified anything)
            setFormData(refreshedFormData);
          }
        } catch (refreshError) {
          console.warn('Failed to refresh task detail after save:', refreshError);
          // Fallback: use current formData if refresh fails
          setOriginalFormData(cloneDeep(formData));
        }
      } else if (result?.success) {
        // If refresh is not available (no snippetId/taskId), use current formData
        // This prevents false positives when checkForChanges() is called later
        setOriginalFormData(cloneDeep(formData));
      }
      
      setFormChanged(false);
      
      if (onFormChange) {
        onFormChange(false);
      }
    } catch (err) {
      setError(err.message || 'Failed to save task details');
    } finally {
      setSaving(false);
    }
  };

  // Form validation methods for external access
  const getFormData = () => {
    return formData;
  };

  const isFormValid = async () => {
    try {
      // Validate the form data using the comprehensive validation utility
      const validation = validateWorkflowTaskDefinition(formData);
      
      if (!validation.isValid) {
        // Set field-specific errors for display
        setFieldErrors(validation.errors);
        
        // Set general error message
        setError(Object.values(validation.errors).join('; '));
        
        return false;
      }
      
      // Clear any existing errors
      setError(null);
      setFieldErrors({});
      return true;
    } catch (err) {
      console.error('Error during form validation:', err);
      setError('Validation error occurred');
      return false;
    }
  };


  // Task type detection using utility functions
  const taskTypeFlags = getTaskTypeFlags(formData.Type);
  const { 
    isActionTask, 
    isNotificationTask, 
    isCloseTask, 
    isSectionTask, 
    isReviewTask, 
    isStepTask, 
    isRouteToTask,
    isEditTask,
    isApproveTask,
    isGoToTask,
    isIfTask
  } = taskTypeFlags;


  // Handle cancel - delegate to parent without showing local confirmation
  const handleCancel = () => {
    console.log('SnippetTaskDetail.handleCancel called', { hasOnCancel: !!onCancel });
    // Always call parent's onCancel handler
    // The parent will handle confirmation dialogs and API calls
    if (onCancel) {
      onCancel();
    } else {
      console.warn('SnippetTaskDetail.handleCancel - onCancel prop not provided!');
    }
  };


  if (loading) {
    return (
      <Box className="snippet-task-detail-loading" sx={{ p: 3 }}>
        <FAWSkeleton variant="rectangular" height={200} />
        <FAWSkeleton variant="text" height={40} sx={{ mt: 2 }} />
        <FAWSkeleton variant="text" height={40} sx={{ mt: 1 }} />
      </Box>
    );
  }

  if (!taskDetail) {
    return (
      <Box className="snippet-task-detail-empty" sx={{ p: 3, textAlign: 'center' }}>
        <FAWTypography variant="h6" color="text.secondary">
          ← Click a task to manage
        </FAWTypography>
      </Box>
    );
  }

  return (
    <FAWErrorBoundary
      title="Task Detail Error"
      message="An error occurred while rendering the task detail form. Please try again."
      showDetails={false}
      onError={(error, errorInfo) => {
        console.error('SnippetTaskDetail Error:', error, errorInfo);
      }}
    >
      <Box className="snippet-task-detail-container" sx={{ 
        backgroundColor: 'white',
        borderRadius: '12px',
        boxShadow: 'none',
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        position: 'relative'
      }}>
        <Box className="snippet-task-detail-content" sx={{ 
          pt: '8px',
          px: '16px',
          pb: '8px',
          display: 'flex', 
          flexDirection: 'column', 
          gap: '16px',
          flex: 1
        }}>

        {/* Error Display */}
        {error && (
          <Alert className="snippet-task-detail-error-alert" severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {/* {formChanged && (
          <Alert className="snippet-task-detail-warning-alert" severity="warning" sx={{ mb: 2 }}>
            You have unsaved changes.
          </Alert>
        )} */}

        {/* Basic Task Fields (Name, Description, Status, Route To, Field Management) */}
        <BasicTaskFields
          formData={formData}
          onFieldChange={handleFieldChange}
          readOnly={readOnly}
          fieldErrors={fieldErrors}
          isCloseTask={isCloseTask}
        />

        {/* Task-Specific Components */}
        {isActionTask && (
          <Box className="snippet-task-detail-action-task">
            <ActionTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isNotificationTask && (
          <Box className="snippet-task-detail-notification-task">
            <NotificationTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isSectionTask && (
          <Box className="snippet-task-detail-section-task">
            <SectionTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isStepTask && (
          <Box className="snippet-task-detail-step-task">
            <StepTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isEditTask && (
          <Box className="snippet-task-detail-edit-task">
            <EditTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isApproveTask && (
          <Box className="snippet-task-detail-approve-task">
            <ApproveTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isReviewTask && (
          <Box className="snippet-task-detail-review-task">
            <ReviewTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isRouteToTask && (
          <Box className="snippet-task-detail-route-to-task">
            <RouteToTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isGoToTask && (
          <Box className="snippet-task-detail-go-to-task">
            <GoToTask 
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isIfTask && (
          <Box className="snippet-task-detail-if-task">
            <IfTask 
              ref={ifTaskRef}
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              workflowDefId={snippetId}
              taskId={taskId}
              isSnippet={true}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}
        {isCloseTask && (
          <Box className="snippet-task-detail-close-task">
            <CloseTask 
              key={`closetask-${formData?.Id}-${formData?.LockId}`}
              formData={formData}
              onFieldChange={handleFieldChange}
              hasRequiredUDFs={() => areRequiredUDFsFilled(formData)}
              readOnly={readOnly}
              fieldErrors={fieldErrors}
              isCloseTask={isCloseTask}
            />
          </Box>
        )}

        </Box>

        {/* Separator line */}
        <Box sx={{ height: '1px', backgroundColor: '#dadada', width: '100%' }} />

        {/* Footer with Action Buttons */}
        {!readOnly && (
          <Box className="snippet-task-detail-footer" sx={{ 
            display: 'flex',
            gap: 2,
            justifyContent: 'space-between',
            alignItems: 'center',
            minHeight: '40px',
            paddingTop: 2
          }}>
            <FAWButton
              className="snippet-task-detail-cancel-btn"
              variant="outlined"
              color="inherit"
              onClick={handleCancel}
              disabled={saving}
              sx={{
                fontWeight: 600,
                fontSize: '16px',
                lineHeight: '25.5px',
                letterSpacing: '0.16px'
              }}
            >
              Cancel
            </FAWButton>
            
            <FAWButton
              className="snippet-task-detail-save-btn"
              variant="contained"
              onClick={handleSave}
              disabled={readOnly || saving}
              loading={saving}
              sx={{
                fontWeight: 600,
                fontSize: '16px',
                lineHeight: '25.5px',
                letterSpacing: '0.16px'
              }}
            >
              Save
            </FAWButton>
          </Box>
        )}

        {/* Saving Loader Overlay */}
        {saving && (
          <Box sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(255, 255, 255, 0.8)',
            backdropFilter: 'blur(2px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000
          }}>
            <FAWLoader 
              size={40} 
              label="Saving snippet task..." 
              inline={false}
            />
          </Box>
        )}
      </Box>
    </FAWErrorBoundary>
  );
});

export default SnippetTaskDetail;
