import React, { useState, useEffect } from 'react';
import {
  Box,
  FormLabel,
  Grid
} from '@mui/material';
import FAWTypography from '../FAWTypography';
import FAWInput from '../FAWInput';
import FAWRadioGroup from '../FAWRadioGroup';
import FAWDrawer from '../FAWDrawer';
import FAWLoader from '../FAWLoader';
import { showToast } from './ToastManager';

/**
 * Shared Adhoc Settings Drawer Component
 * Used by both workflow definitions and snippets
 */
const AdhocSettingsModal = ({ 
  open, 
  onClose, 
  entityId, // Can be workflowId or snippetId
  entityType = 'workflow', // 'workflow' or 'snippet'
  initialData,
  onSave
}) => {
  const [formData, setFormData] = useState({
    expectedDuration: 0,
    allowAdHoc: true
  });
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  // Load data when modal opens
  useEffect(() => {
    if (open && entityId) {
      loadAdhocSettings();
    }
  }, [open, entityId]);

  const loadAdhocSettings = async () => {
    setLoading(true);
    
    try {
      // Try to get data from initialData first
      if (initialData && (initialData.ExpectedDuration !== undefined || initialData.AllowAdHoc !== undefined)) {
        setFormData({
          expectedDuration: initialData.ExpectedDuration || 0,
          allowAdHoc: initialData.AllowAdHoc !== false
        });
        setLoading(false);
        return;
      }

      // Fetch from API if initialData is not available and entityType is workflow
      if (entityType === 'workflow' && entityId) {
        try {
          const response = await fetch(`/WorkflowDef/GetWorkflowDefinitionApi?id=${entityId}`);
          if (!response.ok) {
            throw new Error('Failed to load workflow definition');
          }

          const data = await response.json();
          if (data.success && data.data) {
            setFormData({
              expectedDuration: data.data.ExpectedDuration || 0,
              allowAdHoc: data.data.AllowAdHoc !== false
            });
          } else {
            // Fallback to defaults if API fails
            setFormData({
              expectedDuration: 0,
              allowAdHoc: true
            });
          }
        } catch (apiError) {
          // Fallback to defaults if API call fails
          setFormData({
            expectedDuration: 0,
            allowAdHoc: true
          });
        }
      } else {
        // For snippets, use default values (API not implemented yet)
        setFormData({
          expectedDuration: 0,
          allowAdHoc: true
        });
      }
    } catch (err) {
      showToast.error('Failed to load adhoc settings', 30000);
    } finally {
      setLoading(false);
    }
  };

  const handleFieldChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSave = async () => {
    setSaving(true);

    try {
      // Validate form
      if (formData.expectedDuration < 0) {
        const errorMessage = 'Expected duration must be a positive number';
        showToast.error(errorMessage, 30000);
        setSaving(false);
        return;
      }

      // Determine the correct API endpoint based on entity type
      const endpoint = entityType === 'snippet' 
        ? '/WorkflowTaskDefSnippet/SaveAdhocSettings' // This would need to be implemented
        : '/WorkflowDef/SaveAdhocSettingsApi';
      
      // Convert boolean to capitalized string for .NET parsing (True/False)
      const allowAdHocValue = formData.allowAdHoc ? 'True' : 'False';
      
      const bodyParams = entityType === 'snippet'
        ? { 
            snippetId: entityId, 
            expectedDuration: formData.expectedDuration.toString(),
            allowAdHoc: allowAdHocValue
          }
        : { 
            workflowDefId: entityId.toString(), 
            expectedDuration: formData.expectedDuration.toString(),
            allowAdHoc: allowAdHocValue
          };

      const headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
      };

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: headers,
        body: new URLSearchParams(bodyParams)
      });

      if (!response.ok) {
        throw new Error('Failed to save settings');
      }

      const data = await response.json();
      
      if (!data.success) {
        throw new Error(data.message || 'Failed to save settings');
      }

      // Show success toast
      showToast.success(data.message || 'Ad-hoc settings saved successfully', 30000);

      // Call the save handler for any additional processing
      if (onSave) {
        await onSave({
          ...formData,
          entityId,
          entityType
        });
      }

      onClose();
    } catch (err) {
      const errorMessage = err.message || 'Failed to save settings';
      showToast.error(errorMessage, 30000);
    } finally {
      setSaving(false);
    }
  };

  const handleCancel = () => {
    // Reset form data to default values
    setFormData({
      expectedDuration: 0,
      allowAdHoc: true
    });
    onClose();
  };

  // Define drawer actions
  const drawerActions = [
    {
      text: 'Cancel',
      variant: 'outlined',
      color: 'inherit',
      onClick: handleCancel,
      disabled: saving
    },
    {
      text: 'Save',
      variant: 'contained',
      onClick: handleSave,
      disabled: saving,
      loading: saving,
      handlerType: 'custom',
      bypassFormSubmit: true
    }
  ];

  const drawerContent = (
    <Box sx={{ p: 3, position: 'relative' }}>
      {/* Loading State (initial load) */}
      {loading ? (
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '200px' }}>
          <FAWLoader label="Loading workflow settings..." inline={false} />
        </Box>
      ) : saving ? (
        /* Saving State */
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '200px' }}>
          <FAWLoader label="Saving adhoc settings..." inline={false} />
        </Box>
      ) : (
        /* Form Content */
        <>
          {/* Expected Duration */}
          <Grid container spacing={2} sx={{ mb: 3 }}>
            <Grid item xs={4}>
              <FAWTypography variant="body2" sx={{ pt: 1, fontSize: '14px', fontWeight: 500 }}>
                Expected Duration
              </FAWTypography>
            </Grid>
            <Grid item xs={3}>
              <FAWInput
                fullWidth
                type="number"
                value={formData.expectedDuration}
                onChange={(e) => handleFieldChange('expectedDuration', parseInt(e.target.value) || 0)}
                inputProps={{ 
                  min: 0, 
                  max: 1000, 
                  step: 1 
                }}
                disabled={saving || loading}
              />
            </Grid>
            <Grid item xs={5}>
              <FAWTypography variant="body2" sx={{ pt: 1 }}>
                days
              </FAWTypography>
            </Grid>
          </Grid>

          {/* Ad-hoc Changes */}
          <Box sx={{ mb: 3 }}>
            <FormLabel component="legend" sx={{ mb: 1 }}>
              Ad-hoc Changes
            </FormLabel>
            <FAWRadioGroup
              value={formData.allowAdHoc ? 'true' : 'false'}
              onChange={(e) => handleFieldChange('allowAdHoc', e.target.value === 'true')}
              disabled={saving || loading}
              labelSx={{
                fontSize: '14px',
                fontWeight: 500
              }}
              options={[
                { value: 'true', label: 'Allow ad-hoc changes.' },
                { value: 'false', label: 'Disallow ad-hoc changes.' }
              ]}
            />
          </Box>
        </>
      )}
    </Box>
  );

  return (
    <FAWDrawer
      open={open}
      onClose={handleCancel}
      title="Review Workflow Settings"
      width={500}
      anchor="right"
      showCloseButton={true}
      showHeader={true}
      customFooter={true}
      actions={drawerActions}
    >
      {drawerContent}
    </FAWDrawer>
  );
};

export default AdhocSettingsModal;
