import React, { useState } from 'react';
import { Box, Typography, Alert, IconButton, Button } from '@mui/material';
import FAWTooltip from '../../../FAWTooltip';
import { Refresh as RefreshIcon } from '@mui/icons-material';
import FAWAlert from '../../../FAWAlert';
import FAWButton from '../../../FAWButton';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import WorkflowTree from '../../../../Workflow/WorkflowTree';
import SearchUDFModal from '../../../shared/SearchUDFModal';
import AdhocSettingsModal from '../../../shared/AdhocSettingsModal';
import PreconditionsModal from './PreconditionsModal';
import InsertSnippetModal from '../../../shared/InsertSnippetModal';
import SnippetTaskDetail from './SnippetTaskDetail';
import { snippetApi } from '../services/snippetApi';
import { showToast } from '../../../shared/ToastManager';
import { getTaskTypeName } from '../../shared/utils/taskTypeUtils';
import FAWTypography from '../../../FAWTypography';

const SnippetTaskManagementSection = ({
  snippetId,
  snippetTreeData,
  currentTask,
  taskDetailLoading,
  taskDetail,
  setTaskDetail,
  taskFetchError,
  formChanged,
  setFormChanged,
  taskDetailRef,
  searchUDFModalOpen,
  adhocSettingsModalOpen,
  preconditionsModalOpen,
  insertSnippetModalOpen,
  onNodeSelect,
  onTreeAction,
  onTreeError,
  onSearchUDFOpen,
  onSearchUDFClose,
  onAdhocSettingsOpen,
  onAdhocSettingsClose,
  onPreconditionsOpen,
  onPreconditionsClose,
  onInsertSnippetOpen,
  onInsertSnippetClose,
  onTreeDataRefresh,
  onSuccess,
  setConfirmationDialog,
  showTreeOnly = false,
  showContentOnly = false,
  fullPageLoader,
  setFullPageLoader,
  error,
  treeDataError,
  retryTreeData,
  treeLoading,
  setTreeLoading
}) => {
  
  const [treeError, setTreeError] = useState(null);

  const handleTreeError = (error, isTreeDataError = false) => {
    let errorMessage = 'An error occurred while processing the request.';
    
    if (typeof error === 'string') {
      errorMessage = error;
    } else if (error?.message) {
      errorMessage = error.message;
    } else if (error?.response?.data?.message) {
      errorMessage = error.response.data.message;
    } else if (error?.response?.statusText) {
      errorMessage = error.response.statusText;
    }
    
    setTreeError(errorMessage);
    showToast.error(errorMessage, 30000);
  };

  const handleInsertSnippetSave = async (data) => {
    try {
      const result = await snippetApi.insertSnippet(data.snippetId, data.taskId, data.snippetId);
      // Only refresh tree if the operation was successful
      if (result && result.success) {
        showToast.success(result.message || 'Snippet inserted successfully', 30000);
        
        if (onTreeDataRefresh) {
          await onTreeDataRefresh();
        }
      } else {
        throw new Error(result?.message || 'Failed to insert snippet');
      }
    } catch (error) {
      showToast.error(error.message || 'Failed to insert snippet', 30000);
      // Don't refresh tree on error
    }
  };


  React.useEffect(() => {
    const handleAddTaskRequest = (event) => {
      const { snippetId: eventSnippetId, parentTaskId, taskType } = event.detail;
      
      if (eventSnippetId && taskType) {
        const taskTypeName = getTaskTypeName(taskType);
        const addTaskFunction = async () => {
          setFullPageLoader({
            open: true,
            message: `Creating ${taskTypeName} task...`
          });
          setTreeError(null);
          try {
            const result = await snippetApi.addTask(eventSnippetId, parentTaskId, taskType);
            
            // Only proceed if the task was successfully created
            if (result.success) {
              showToast.success(result.message || `${taskTypeName} task added successfully`, 30000);
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
              
              if (result.taskId && onNodeSelect) {
                // Wait a bit for the tree to re-render with the new data
                await new Promise(resolve => setTimeout(resolve, 100));
                
                const newTask = {
                  id: result.taskId,
                  Name: `New ${taskType}`,
                  Type: taskType,
                };
                
                try {
                  onNodeSelect(newTask);
                } catch (error) {
                  console.error('ADD SNIPPET TASK: Error in onNodeSelect:', error);
                }
                
                const currentUrl = new URL(window.location.href);
                currentUrl.searchParams.set('taskId', result.taskId);
                window.history.replaceState({}, '', currentUrl.toString());
                
                const event = new CustomEvent('taskIdUpdated', {
                  detail: { taskId: result.taskId, snippetId: eventSnippetId }
                });
                window.dispatchEvent(event);
              }
            } else {
              // Handle API success=false case
              const errorMessage = result.message || `Failed to create ${taskTypeName} task`;
              handleTreeError(errorMessage);
            }
          } catch (error) {
            const errorMessage = error.message || `Failed to create ${taskTypeName} task`;
            handleTreeError(errorMessage);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        };
        
        addTaskFunction();
      }
    };

    window.addEventListener('addTaskRequested', handleAddTaskRequest);

    return () => {
      window.removeEventListener('addTaskRequested', handleAddTaskRequest);
    };
  }, [onTreeDataRefresh, onNodeSelect]);


  const hasValidSnippetId = snippetId && snippetId !== 0;

  if (!hasValidSnippetId) {
    return null;
  }

  const renderWorkflowTree = () => (
      <FAWErrorBoundary
        title="Snippet Tree Error"
      message="An error occurred while rendering the snippet tree. The tree functionality may be limited."
        showDetails={false}
      onError={(error, errorInfo) => {
        onTreeError(error);
      }}
      >
      <WorkflowTree
          currentTask={currentTask}
        readOnly={false}
        treeDataJson={snippetTreeData}
        handleNodeSelect={onNodeSelect}
        handleAction={onTreeAction}
        loading={!snippetTreeData || treeLoading}
        workItem={{ 
          id: snippetId || 0, 
          allowAdhocFlowEdit: true,
          isEditable: true 
        }}
        height="100%"
        isSnippet={true}
        showSearchBar={false}
        isDefinitionMode={true}
        updateTreeAsync={async (nodeId, parentId, index, treeData, handleError) => {
          setTreeLoading(true);
          setTreeError(null);
          try {
            const result = await snippetApi.updateSnippetTreeStructure(snippetId, nodeId, parentId, index);
            
            if (result.success) {
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
              onSuccess(result.message || 'Tree structure updated successfully');
            } else {
              throw new Error(result.message || 'Failed to update tree structure');
            }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        removeTaskAsync={async (snippetId, taskId, handleError) => {
          if (setConfirmationDialog) {
            setConfirmationDialog({
              open: true,
              title: 'Confirm Removal',
              message: 'Are you sure you want to remove this task from the snippet?',
              onConfirm: async () => {
                setConfirmationDialog({ open: false });
                setFullPageLoader({
                  open: true,
                  message: 'Removing task...'
                });
                setTreeError(null);
                
                try {
                  const result = await snippetApi.removeTask(snippetId, taskId);
                  
                  // Only refresh tree if the operation was successful
                  if (result && result.success !== false) {
                    showToast.success(result.message || 'Task removed successfully', 30000);
                    
                    if (onTreeDataRefresh) {
                      await onTreeDataRefresh();
                    }
                  } else {
                    throw new Error(result?.message || 'Failed to remove task');
                  }
                } catch (error) {
                  handleTreeError(error);
                } finally {
                  setFullPageLoader(prev => ({ ...prev, open: false }));
                }
              },
              onCancel: () => {
                setConfirmationDialog({ open: false });
              },
              confirmText: 'Yes, Remove',
              cancelText: 'Cancel',
              severity: 'error'
            });
          } else {
            setFullPageLoader({
              open: true,
              message: 'Removing task...'
            });
            setTreeError(null);
            try {
              const result = await snippetApi.removeTask(snippetId, taskId);
              // Only refresh tree if the operation was successful
              if (result && result.success !== false) {
                onSuccess(result.message || 'Task removed successfully');
                if (onTreeDataRefresh) {
                  await onTreeDataRefresh();
                }
              } else {
                throw new Error(result?.message || 'Failed to remove task');
              }
            } catch (error) {
              handleTreeError(error);
            } finally {
              setFullPageLoader(prev => ({ ...prev, open: false }));
            }
          }
        }}
        restoreTaskAsync={async (snippetId, taskId, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Restoring task...'
          });
          setTreeError(null);
          try {
            const result = await snippetApi.restoreTask(snippetId, taskId);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              onSuccess(result.message || 'Task restored successfully');
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to restore task');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        addTaskAsync={async (snippetId, parentTaskId, taskType, handleError) => {
          const taskTypeName = getTaskTypeName(taskType);
          setFullPageLoader({
            open: true,
            message: `Creating ${taskTypeName} task...`
          });
          setTreeError(null);
          try {
            const result = await snippetApi.addTask(snippetId, parentTaskId, taskType);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              onSuccess(result.message || `${taskTypeName} task added successfully`);
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to add task');
            }
            
           if (result.taskId && onNodeSelect) {
             // Wait a bit for the tree to re-render with the new data
             await new Promise(resolve => setTimeout(resolve, 300));
             
             const newTask = {
               id: result.taskId,
               Name: `New ${taskType}`,
               Type: taskType,
             };
             
             try {
               onNodeSelect(newTask);
             } catch (error) {
               console.error('ADD SNIPPET TASK ASYNC: Error in onNodeSelect:', error);
               // Show a warning but don't fail the entire operation
               showToast.warning('Task created but auto-selection failed. Please manually select the new task.', 5000);
             }
             
             // Update URL and dispatch event
             const currentUrl = new URL(window.location.href);
             currentUrl.searchParams.set('taskId', result.taskId);
             window.history.replaceState({}, '', currentUrl.toString());
             
             const event = new CustomEvent('taskIdUpdated', {
               detail: { taskId: result.taskId, snippetId: snippetId }
             });
             window.dispatchEvent(event);
           }
          } catch (error) {
            const errorMessage = error.message || `Failed to create ${taskTypeName} task`;
            handleTreeError(errorMessage);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        saveTaskPredecessorAsync={(() => {
          const saveFn = async (snippetId, taskId, finalPredecessorIds, handleError) => {
            setFullPageLoader({
              open: true,
              message: 'Saving predecessors...'
            });
            setTreeError(null);
            try {
              const result = await snippetApi.saveTaskPredecessors(snippetId, taskId, finalPredecessorIds);
              // Only refresh tree if the operation was successful
              if (result && result.success) {
                onSuccess(result.message || 'Predecessors saved successfully');
                if (onTreeDataRefresh) {
                  await onTreeDataRefresh();
                }
              } else {
                throw new Error(result?.message || 'Failed to save predecessors');
              }
            } catch (error) {
              handleTreeError(error);
              // Don't refresh tree on error
            } finally {
              setFullPageLoader(prev => ({ ...prev, open: false }));
            }
          };
          saveFn.getTaskPredecessors = (snippetId, taskId) => snippetApi.getTaskPredecessors(snippetId, taskId);
          return saveFn;
        })()}
        loadSnippetsAsync={async (snippetId) => {
          try {
            const snippets = await snippetApi.getSnippets(snippetId);
            return snippets;
          } catch (error) {
            handleTreeError(error);
            return [];
          }
        }}
        moveTaskAsync={async (snippetId, taskId, isUp, handleError) => {
          const moveMessage = isUp ? 'Moving task up...' : 'Moving task down...';
          setFullPageLoader({
            open: true,
            message: moveMessage
          });
          setTreeError(null);
          try {
            const result = await snippetApi.moveTask(snippetId, taskId, isUp);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              const successMessage = isUp ? 'Task moved up successfully' : 'Task moved down successfully';
              onSuccess(result.message || successMessage);
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to move task');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        moveTaskToSectionAsync={async (snippetId, sourceId, targetId, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Moving task to section...'
          });
          setTreeError(null);
          try {
            const result = await snippetApi.moveTaskToSection(snippetId, sourceId, targetId);
            // Only refresh tree if the operation was successful
            if (result && result.success !== false) {
              onSuccess(result.message || 'Task moved to section successfully');
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result?.message || 'Failed to move task to section');
            }
          } catch (error) {
            handleTreeError(error);
            // Don't refresh tree on error
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        saveInsertSnippetAsync={async (snippetData, handleError) => {
          setFullPageLoader({
            open: true,
            message: 'Inserting snippet...'
          });
          setTreeError(null);
          
          try {
            const result = await snippetApi.insertSnippet(
              snippetData.containerId, 
              snippetData.taskId, 
              snippetData.snippetId
            );
            
            if (result.success) {
              showToast.success(result.message || 'Snippet inserted successfully');
              
              if (onTreeDataRefresh) {
                await onTreeDataRefresh();
              }
            } else {
              throw new Error(result.message || 'Failed to insert snippet');
            }
          } catch (error) {
            handleTreeError(error);
          } finally {
            setFullPageLoader(prev => ({ ...prev, open: false }));
          }
        }}
        handleError={onTreeError}
        />
      </FAWErrorBoundary>
  );

  if (showTreeOnly) {
    return (
      <Box>
        {treeLoading && (
          <Box sx={{ p: 2 }}>
            <FAWSkeleton variant="workflowTree" />
          </Box>
        )}

        {/* Show retry button when tree data failed to load */}
        {!treeLoading && treeDataError && (
          <Box sx={{ 
            p: 3, 
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center', 
            justifyContent: 'center',
            height: '200px',
            textAlign: 'center'
          }}>
            <Typography variant="body1" color="text.secondary" sx={{ mb: 2 }}>
              Failed to load snippet tree data
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
              {treeDataError}
            </Typography>
            <FAWTooltip title="Retry loading tree data">
              <IconButton
                onClick={() => retryTreeData(setTreeLoading)}
                sx={{
                  backgroundColor: '#f5f5f5',
                  '&:hover': {
                    backgroundColor: '#e0e0e0'
                  }
                }}
              >
                <RefreshIcon />
              </IconButton>
            </FAWTooltip>
          </Box>
        )}

        {/* {(error || treeError) && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => {
            setTreeError(null);
          }}>
            {error || treeError}
          </Alert>
        )} */}

        {(() => {
          const shouldRender = !treeLoading && !treeDataError;
          return shouldRender && renderWorkflowTree();
        })()}
      </Box>
    );
  }

  if (showContentOnly) {
    return (
      <Box>
        {currentTask && (
          <Box sx={{ mt: 2 }}>
            <SnippetTaskDetail
              ref={taskDetailRef}
              taskDetail={taskDetail}
              loading={taskDetailLoading}
              snippetId={snippetId}
              taskId={currentTask?.id}
              onFormChange={(changed) => {
                if (setFormChanged) {
                  setFormChanged(changed);
                }
              }}
              onSave={async (formData) => {
                try {
                  const result = await snippetApi.saveTaskDetail(formData);
                  
                  if (result.success) {
                    onSuccess(result.message || 'Task details saved successfully');
                    
                    // Refresh tree data to reflect name changes in the left panel
                    if (onTreeDataRefresh) {
                      if (setTreeLoading) setTreeLoading(true);
                      try {
                        const refreshedTreeData = await onTreeDataRefresh();
                        
                        // Update currentTask with fresh data from tree after refresh
                        // This ensures the header shows the updated name
                        // Wrap in try-catch to prevent tree refresh errors from breaking the save flow
                        try {
                          if (currentTask?.id && onNodeSelect) {
                            const treeDataToSearch = refreshedTreeData || snippetTreeData;
                            if (treeDataToSearch) {
                              const findTaskInTree = (nodes, targetId) => {
                                for (const node of nodes) {
                                  if (String(node.id) === String(targetId)) {
                                    return node;
                                  }
                                  if (node.children && node.children.length > 0) {
                                    const found = findTaskInTree(node.children, targetId);
                                    if (found) return found;
                                  }
                                }
                                return null;
                              };
                              
                              const updatedTask = findTaskInTree(treeDataToSearch, currentTask.id);
                              if (updatedTask && String(updatedTask.id) === String(currentTask.id)) {
                                // Skip confirmation dialog since we just saved successfully
                                onNodeSelect(updatedTask, { skipConfirmation: true });
                              }
                            }
                          }
                        } catch (updateError) {
                          // Log but don't throw - save was successful, tree update is just for UI
                          console.warn('Failed to update currentTask after tree refresh:', updateError);
                        }
                      } catch (refreshError) {
                        // Log but don't throw - save was successful, tree refresh is just for UI
                        console.warn('Failed to refresh tree data after save:', refreshError);
                      } finally {
                        if (setTreeLoading) setTreeLoading(false);
                      }
                    }
                    
                    return result; // Return result so handleSave can check success
                  } else {
                    // Handle save failure
                    throw new Error(result.message || 'Failed to save task details');
                  }
                } catch (error) {
                  console.error('Error saving task details:', error);
                  throw error;
                }
              }}
              onTaskDetailUpdate={(updatedTaskDetail) => {
                if (setTaskDetail) {
                  setTaskDetail(updatedTaskDetail);
                }
              }}
              onCancel={() => {
              }}
              readOnly={false}
            />
          </Box>
        )}
      </Box>
    );
  }

  return (
    <Box sx={{ 
      display: 'flex', 
      height: '100%', 
      gap: 2,
      width: '100%',
      maxWidth: '100%',
      boxSizing: 'border-box',
      overflow: 'hidden'
    }}>
      <Box sx={{ 
        flex: '0 0 calc(40% - 8px)',
        minWidth: 0,
        maxWidth: 'calc(40% - 8px)',
        display: 'flex',
        flexDirection: 'column',
        borderRight: '1px solid #dadada',
        pr: 2,
        boxSizing: 'border-box',
        overflow: 'hidden'
      }}>
        {treeLoading && (
          <Box sx={{ p: 2 }}>
            <FAWSkeleton variant="workflowTree" />
          </Box>
        )}

        {(error || treeError) && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => {
            setTreeError(null);
          }}>
            {error || treeError}
          </Alert>
        )}

        {!treeLoading && !treeDataError && renderWorkflowTree()}
      </Box>

      <Box sx={{ 
        flex: '0 0 calc(60% - 8px)',
        minWidth: 0,
        maxWidth: 'calc(60% - 8px)',
        display: 'flex',
        flexDirection: 'column',
        boxSizing: 'border-box',
        overflow: 'hidden'
      }}>
        {!currentTask && (
          <Box sx={{ 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            height: '100%',
            color: '#666',
            fontSize: '16px',
            textAlign: 'center'
          }}>
            <Box>
              <FAWTypography variant="h6" sx={{ mb: 1, color: '#999' }}>
                No Task Selected
              </FAWTypography>
              <FAWTypography variant="body2" sx={{ color: '#999' }}>
                Click a task in the tree to view and manage its details
              </FAWTypography>
            </Box>
          </Box>
        )}

        {currentTask && taskFetchError && (
          <Box sx={{ 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            height: '100%',
            color: '#666',
            fontSize: '16px',
            textAlign: 'center'
          }}>
            <Box>
              <FAWTypography variant="h6" sx={{ mb: 1, color: '#d32f2f' }}>
                Unable to Fetch Task Details
              </FAWTypography>
              <FAWTypography variant="body2" sx={{ color: '#666', mb: 2 }}>
                {taskFetchError}
              </FAWTypography>
              <Button
                variant="contained"
                startIcon={<RefreshIcon />}
                onClick={() => {
                  if (currentTask) {
                    onNodeSelect(currentTask);
                  }
                }}
                sx={{
                  backgroundColor: '#1976d2',
                  '&:hover': {
                    backgroundColor: '#1565c0'
                  }
                }}
              >
                Retry
              </Button>
            </Box>
          </Box>
        )}

        {currentTask && (
          <SnippetTaskDetail
            ref={taskDetailRef}
            taskDetail={taskDetail}
            loading={taskDetailLoading}
            snippetId={snippetId}
            taskId={currentTask?.id}
            onFormChange={(changed) => {
              if (setFormChanged) {
                setFormChanged(changed);
              }
            }}
            onSave={async (formData) => {
              setFullPageLoader({
                open: true,
                message: 'Saving task details...'
              });
              try {
                const result = await snippetApi.saveTaskDetail(formData);
                
                if (result.success) {
                  onSuccess(result.message || 'Task details saved successfully');
                  
                  // Refresh tree data to reflect name changes in the left panel and header
                  if (onTreeDataRefresh) {
                    if (setTreeLoading) setTreeLoading(true);
                    try {
                      const refreshedTreeData = await onTreeDataRefresh();
                      
                      // Update currentTask with fresh data from tree after refresh
                      // This ensures the header shows the updated name
                      // Wrap in try-catch to prevent tree refresh errors from breaking the save flow
                      try {
                        if (currentTask?.id && onNodeSelect) {
                          const treeDataToSearch = refreshedTreeData || snippetTreeData;
                          if (treeDataToSearch) {
                            const findTaskInTree = (nodes, targetId) => {
                              for (const node of nodes) {
                                if (String(node.id) === String(targetId)) {
                                  return node;
                                }
                                if (node.children && node.children.length > 0) {
                                  const found = findTaskInTree(node.children, targetId);
                                  if (found) return found;
                                }
                              }
                              return null;
                            };
                            
                            const updatedTask = findTaskInTree(treeDataToSearch, currentTask.id);
                            if (updatedTask && String(updatedTask.id) === String(currentTask.id)) {
                              // Skip confirmation dialog since we just saved successfully
                              onNodeSelect(updatedTask, { skipConfirmation: true });
                            }
                          }
                        }
                      } catch (updateError) {
                        // Log but don't throw - save was successful, tree update is just for UI
                        console.warn('Failed to update currentTask after tree refresh:', updateError);
                      }
                    } catch (refreshError) {
                      // Log but don't throw - save was successful, tree refresh is just for UI
                      console.warn('Failed to refresh tree data after save:', refreshError);
                    } finally {
                      if (setTreeLoading) setTreeLoading(false);
                    }
                  }
                  
                  return result; // Return result so handleSave can check success
                } else {
                  // Handle save failure
                  throw new Error(result.message || 'Failed to save task details');
                }
              } catch (error) {
                console.error('Error saving task details:', error);
                throw error;
              } finally {
                setFullPageLoader(prev => ({ ...prev, open: false }));
              }
            }}
            onTaskDetailUpdate={(updatedTaskDetail) => {
              if (setTaskDetail) {
                setTaskDetail(updatedTaskDetail);
              }
            }}
            onCancel={() => {
              // Handle cancel - could reset form or close detail view
            }}
            readOnly={false}
          />
        )}
      </Box>

      <Box sx={{ display: 'flex', gap: 2, mb: 2, flexWrap: 'wrap', p: 2 }}>
        <FAWButton
          variant="outlined"
          color="primary"
          onClick={onSearchUDFOpen}
          disabled={!hasValidSnippetId}
          sx={{ minWidth: 120 }}
        >
          Find Additional Fields
        </FAWButton>
        
        <FAWButton
          variant="outlined"
          color="secondary"
          onClick={onAdhocSettingsOpen}
          disabled={!hasValidSnippetId}
          sx={{ minWidth: 120 }}
        >
          Adhoc Settings
        </FAWButton>
        
        <FAWButton
          variant="outlined"
          color="secondary"
          onClick={onPreconditionsOpen}
          disabled={!hasValidSnippetId}
          sx={{ minWidth: 120 }}
        >
          Preconditions
        </FAWButton>
        
        <FAWButton
          variant="outlined"
          color="secondary"
          onClick={onInsertSnippetOpen}
          disabled={!hasValidSnippetId}
          sx={{ minWidth: 120 }}
        >
          Insert Snippet
        </FAWButton>
      </Box>

      <SearchUDFModal
        open={searchUDFModalOpen && hasValidSnippetId}
        onClose={onSearchUDFClose}
        entityId={snippetId}
        entityType="snippet"
      />

      <AdhocSettingsModal
        open={adhocSettingsModalOpen && hasValidSnippetId}
        onClose={onAdhocSettingsClose}
        entityId={snippetId}
        entityType="snippet"
      />

      <PreconditionsModal
        open={preconditionsModalOpen && hasValidSnippetId}
        onClose={onPreconditionsClose}
        entityId={snippetId}
      />

      <InsertSnippetModal
        open={insertSnippetModalOpen && hasValidSnippetId}
        onClose={onInsertSnippetClose}
        entityId={snippetId}
        entityType="snippet"
        taskId={currentTask?.id}
        getSnippetsApi={snippetApi.getSnippets}
        onSave={handleInsertSnippetSave}
      />

      </Box>
  );
};

export default SnippetTaskManagementSection;
